SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The potential at the centre of a uniformly charged ring of total charge Q and radius R is _____.", "explanation": "Every point on the ring is at distance R from the centre (by the definition of a ring). Since potential is a scalar, V = kQ/R (no vector cancellation). This is the same as the potential at distance R from a point charge Q, because all charge elements are equidistant from the centre.", "correct_answer": "B", "concept_tags": ["ring-potential", "centre", "scalar-addition"], "payload": {"question_id": "cuet-phy-elec-potential-35", "subtopic": "Potential due to continuous distribution", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "kQ/R", "is_correct": true}, {"key": "C", "text": "kQ/R²", "is_correct": false}, {"key": "D", "text": "2kQ/R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The electric field at the centre of a ring is zero (by symmetry), but the potential is not. Don''t confuse E = 0 with V = 0.", "misconception": "Thinking zero field at centre means zero potential"}, {"option_key": "C", "hint": "kQ/R² has dimensions of electric field, not potential. Potential = kQ/R.", "misconception": "Confusing field and potential formulas"}, {"option_key": "D", "hint": "There is no factor of 2. Each charge element dq at distance R contributes k·dq/R, and summing gives kQ/R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A charge of 10 μC is placed at the origin. The potential at a point 0.3 m from the charge is _____ V. (Take k = 9 × 10⁹ N m² C⁻²)", "explanation": "Using V = kq/r = 9 × 10⁹ × 10 × 10⁻⁶ / 0.3 = 9 × 10⁹ × 10⁻⁵ / 0.3 = 9 × 10⁴ / 0.3 = 3 × 10⁵ V. The potential is 3 × 10⁵ V or 300000 V.", "correct_answer": "D", "concept_tags": ["electric potential calculation", "point charge", "numerical"], "payload": {"question_id": "cuet-phy-elec-potential-36", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "3 × 10⁴", "is_correct": false}, {"key": "B", "text": "9 × 10⁵", "is_correct": false}, {"key": "C", "text": "3 × 10⁶", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁴ is ten times too small. Check the power of ten in the calculation: 9 × 10⁹ × 10⁻⁵ = 9 × 10⁴, and dividing by 0.3 gives 3 × 10⁵.", "misconception": "Error in handling powers of ten"}, {"option_key": "B", "hint": "9 × 10⁵ would result from not dividing by 0.3 or using an incorrect distance.", "misconception": null}, {"option_key": "C", "hint": "3 × 10⁶ is ten times too large, likely from using the charge as 100 μC instead of 10 μC.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory experiment, a student places a +5 μC charge at point A and a +10 μC charge at point B, separated by a distance of 1 m. She wants to find a point on the line joining A and B where the electric potential is zero. She assumes both charges are in free space.\n\nThe student''s observation should be that:", "explanation": "Since both charges are positive, the potential V = kq₁/r₁ + kq₂/r₂ is always positive at every point on the line joining them (and everywhere in space, since both terms are positive). There is no point where the net potential is zero. For potential to be zero between two charges, the charges must be of opposite sign.", "correct_answer": "C", "concept_tags": ["superposition of potential", "like charges", "zero potential"], "payload": {"question_id": "cuet-phy-elec-potential-37", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "The zero potential point lies between A and B at 1/3 m from A", "is_correct": false}, {"key": "B", "text": "The zero potential point lies between A and B at the midpoint", "is_correct": false}, {"key": "C", "text": "No point on the line joining A and B has zero potential", "is_correct": true}, {"key": "D", "text": "The zero potential point lies outside AB at 1 m from B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the null point for electric field (not potential) between charges of different magnitudes, and even then only for opposite charges would potential be zero between them.", "misconception": "Confusing zero field point with zero potential point"}, {"option_key": "B", "hint": "At the midpoint, both positive charges contribute positive potentials, so the net potential is positive, not zero.", "misconception": "Assuming symmetry implies zero potential"}, {"option_key": "D", "hint": "Even outside the charges, both positive charges contribute positive potentials at all points, so the potential cannot be zero anywhere.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "An electron (charge = −1.6 × 10⁻¹⁹ C, mass = 9.1 × 10⁻³¹ kg) is accelerated from rest through a potential difference of 100 V. Calculate its final kinetic energy and speed.", "explanation": "KE = |q|ΔV = 1.6 × 10⁻¹⁹ × 100 = 1.6 × 10⁻¹⁷ J = 100 eV. Speed: ½mv² = KE, so v = √(2KE/m) = √(2 × 1.6 × 10⁻¹⁷ / 9.1 × 10⁻³¹) = √(3.516 × 10¹³) = 5.93 × 10⁶ m/s.", "correct_answer": "D", "concept_tags": ["electron-acceleration", "kinetic-energy", "potential-difference"], "payload": {"question_id": "cuet-phy-elec-potential-38", "subtopic": "Motion in electric potential", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁵ m/s", "is_correct": false}, {"key": "B", "text": "KE = 1.6 × 10⁻¹⁹ J; v = 5.93 × 10⁶ m/s", "is_correct": false}, {"key": "C", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁷ m/s", "is_correct": false}, {"key": "D", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁶ m/s", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The KE is correct but the speed is off by a factor of 10. Check: v = √(2 × 1.6 × 10⁻¹⁷/9.1 × 10⁻³¹) ≈ 5.93 × 10⁶, not 10⁵.", "misconception": "Error in square root calculation"}, {"option_key": "B", "hint": "KE = qV = 1.6 × 10⁻¹⁹ × 100 = 1.6 × 10⁻¹⁷ J, not 10⁻¹⁹ J. You forgot to multiply by the potential difference.", "misconception": "Using the charge value directly as KE without multiplying by V"}, {"option_key": "C", "hint": "v = 5.93 × 10⁷ m/s is about 20% of the speed of light, which is too high for 100V acceleration. Check the exponent in the square root.", "misconception": "Error in exponent during square root calculation"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following in order of increasing electric potential (lowest first) for a positive point charge Q placed at the origin:\n\n1. A point at distance 4R from Q\n2. A point at distance R from Q\n3. A point at distance 2R from Q\n4. A point at infinity", "explanation": "V = kQ/r for positive Q. V(∞) = 0 (lowest). V(4R) = kQ/(4R). V(2R) = kQ/(2R). V(R) = kQ/R (highest). Increasing order: 0 < kQ/(4R) < kQ/(2R) < kQ/R. So: 4 (infinity) → 1 (4R) → 3 (2R) → 2 (R).", "correct_answer": "B", "concept_tags": ["potential-ordering", "distance-dependence", "positive-charge"], "payload": {"question_id": "cuet-phy-elec-potential-39", "subtopic": "Potential variation with distance", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "2 → 3 → 1 → 4", "is_correct": false}, {"key": "B", "text": "4 → 1 → 3 → 2", "is_correct": true}, {"key": "C", "text": "4 → 3 → 1 → 2", "is_correct": false}, {"key": "D", "text": "1 → 3 → 2 → 4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This gives decreasing order (highest to lowest), not increasing. Point 2 (distance R) has the highest potential.", "misconception": "Reversing the required order"}, {"option_key": "C", "hint": "This swaps items 1 (4R) and 3 (2R). Since V ∝ 1/r, the closer point (2R) has higher potential than the farther point (4R).", "misconception": "Confusing which distance gives higher potential"}, {"option_key": "D", "hint": "This starts with 4R and ends with infinity (V = 0), but infinity has the lowest potential for a positive charge, so it should come first.", "misconception": "Forgetting that V = 0 at infinity is the minimum for positive charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following charge configurations in order of increasing electric potential at a point P located at distance d from each configuration (from lowest to highest potential):", "explanation": "V = kq/d, which is directly proportional to the charge q. For negative charges, V is negative; for positive charges, V is positive. In ascending order: −2kQ/d < −kQ/d < +kQ/d < +2kQ/d, i.e., −2Q → −Q → +Q → +2Q.", "correct_answer": "A", "concept_tags": ["potential-comparison", "charge-sign", "ordering"], "payload": {"question_id": "cuet-phy-elec-potential-40", "subtopic": "Potential due to point charges", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "−2Q → −Q → +Q → +2Q (i.e., 1 → 2 → 3 → 4)", "is_correct": true}, {"key": "B", "text": "+2Q → +Q → −Q → −2Q (i.e., 4 → 3 → 2 → 1)", "is_correct": false}, {"key": "C", "text": "−Q → −2Q → +Q → +2Q (i.e., 2 → 1 → 3 → 4)", "is_correct": false}, {"key": "D", "text": "+Q → +2Q → −Q → −2Q (i.e., 3 → 4 → 2 → 1)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is decreasing order (highest to lowest). The question asks for increasing order.", "misconception": "Reversing the requested order"}, {"option_key": "C", "hint": "−Q gives V = −kQ/d and −2Q gives V = −2kQ/d. Since −2kQ/d < −kQ/d, the −2Q charge gives the lower potential.", "misconception": "Comparing magnitudes instead of signed values"}, {"option_key": "D", "hint": "This places positive potentials before negative ones. Negative values are always less than positive values.", "misconception": "Ignoring the sign of the potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The dimension of capacitance is:", "explanation": "C = Q/V. Dimension of Q = [AT], V = [ML²T⁻³A⁻¹]. So C = [AT]/[ML²T⁻³A⁻¹] = [M⁻¹L⁻²T⁴A²]. This can also be verified: 1 farad = 1 C/V = 1 C²/(J) = 1 A²s⁴/(kg·m²).", "correct_answer": "C", "concept_tags": ["capacitance-dimension", "dimensional-analysis"], "payload": {"question_id": "cuet-phy-elec-capacitor-01", "subtopic": "Capacitance basics", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "[ML²T⁻²A⁻²]", "is_correct": false}, {"key": "B", "text": "[M⁻¹L⁻²T³A²]", "is_correct": false}, {"key": "C", "text": "[M⁻¹L⁻²T⁴A²]", "is_correct": true}, {"key": "D", "text": "[MLT⁻²A⁻¹]", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "[ML²T⁻²A⁻²] is the dimension of inductance (L = V·s/A), not capacitance.", "misconception": "Confusing capacitance with inductance dimensions"}, {"option_key": "B", "hint": "T³ is incorrect — the time exponent should be T⁴ (from T in charge and T⁻³ in voltage denominator).", "misconception": "Arithmetic error in exponent calculation"}, {"option_key": "D", "hint": "[MLT⁻²A⁻¹] is the dimension of magnetic field (B), not capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A conducting slab of thickness t is introduced between the plates of a parallel plate capacitor with plate separation d (t < d). The new capacitance is:", "explanation": "A conducting slab has infinite dielectric constant. It effectively reduces the gap to (d − t), as the field inside the conductor is zero. The capacitance becomes C'' = ε₀A/(d − t). Unlike a dielectric, a conductor completely eliminates the field in its interior.", "correct_answer": "B", "concept_tags": ["conducting-slab", "effective-gap", "capacitance-increase"], "payload": {"question_id": "cuet-phy-elec-capacitor-02", "subtopic": "Conducting slab in capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "ε₀A/d (unchanged)", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": true}, {"key": "C", "text": "ε₀A/(d + t)", "is_correct": false}, {"key": "D", "text": "ε₀A/t", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The conducting slab eliminates the field in its interior, reducing the effective gap. Capacitance must increase, not remain the same.", "misconception": "Thinking the slab has no effect"}, {"option_key": "C", "hint": "d + t would mean the gap increases, but the slab is placed inside the existing gap, reducing the effective air gap to d − t.", "misconception": "Adding instead of subtracting the slab thickness"}, {"option_key": "D", "hint": "ε₀A/t would apply if the conducting slab filled the entire gap except a vanishingly small space. The effective gap is d − t, not t.", "misconception": "Using slab thickness instead of remaining gap"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in a capacitor of capacitance C charged to voltage V is equivalent to the energy stored in the electric field between the plates. The energy per unit volume (energy density) is:", "explanation": "Energy U = ½CV² = ½(ε₀A/d)(Ed)² = ½ε₀E² × (Ad). Volume between plates = Ad. So energy density u = U/(Ad) = ½ε₀E². This is a general result — the energy density of any electric field is ½ε₀E².", "correct_answer": "D", "concept_tags": ["energy-density", "electric-field-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-03", "subtopic": "Energy density", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "ε₀E", "is_correct": false}, {"key": "B", "text": "ε₀E²", "is_correct": false}, {"key": "C", "text": "½ε₀²E²", "is_correct": false}, {"key": "D", "text": "½ε₀E²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E has dimensions of charge/area (surface charge density), not energy/volume.", "misconception": "Dimensional error"}, {"option_key": "B", "hint": "Missing the factor of ½. The correct expression is ½ε₀E², derived from integrating the work to build the field.", "misconception": "Forgetting the factor of ½ in energy density"}, {"option_key": "C", "hint": "½ε₀²E² has ε₀ squared, which gives wrong dimensions. Energy density requires exactly one power of ε₀.", "misconception": "Squaring ε₀ instead of E"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a cylindrical capacitor of length L with inner radius a and outer radius b is:", "explanation": "For a cylindrical capacitor, V = (λ/2πε₀)ln(b/a), where λ = Q/L. So C = Q/V = 2πε₀L/ln(b/a). This is analogous to the parallel plate formula but adapted for cylindrical geometry. The capacitance is proportional to length L.", "correct_answer": "A", "concept_tags": ["cylindrical-capacitor", "logarithmic-formula"], "payload": {"question_id": "cuet-phy-elec-capacitor-04", "subtopic": "Cylindrical capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "2πε₀L/ln(b/a)", "is_correct": true}, {"key": "B", "text": "4πε₀L/ln(b/a)", "is_correct": false}, {"key": "C", "text": "2πε₀L/(b − a)", "is_correct": false}, {"key": "D", "text": "ε₀L/(b − a)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4πε₀ appears in the spherical capacitor formula, not the cylindrical one. The cylindrical geometry uses 2πε₀.", "misconception": "Confusing cylindrical with spherical geometry factor"}, {"option_key": "C", "hint": "The denominator should be ln(b/a), not (b − a). The logarithm arises from integrating E = λ/(2πε₀r) from a to b.", "misconception": "Using linear gap instead of logarithmic ratio"}, {"option_key": "D", "hint": "This lacks the 2π factor and uses (b−a) instead of ln(b/a). Both are incorrect for a cylindrical geometry.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor is given by C = ε₀A/d. If the area of each plate is doubled, the capacitance:", "explanation": "Since C = ε₀A/d, the capacitance is directly proportional to the area A of the plates. If A is doubled, C also doubles. This is because a larger plate area can store more charge for the same potential difference.", "correct_answer": "B", "concept_tags": ["parallel plate capacitor", "capacitance formula", "plate area"], "payload": {"question_id": "cuet-phy-elec-capacitor-05", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Remains the same", "is_correct": false}, {"key": "B", "text": "Becomes double", "is_correct": true}, {"key": "C", "text": "Becomes half", "is_correct": false}, {"key": "D", "text": "Becomes four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Capacitance depends on plate area, so changing the area will change the capacitance.", "misconception": "Thinking capacitance is independent of plate geometry"}, {"option_key": "C", "hint": "Capacitance is directly proportional to A, not inversely proportional. Doubling A increases C.", "misconception": "Confusing direct and inverse proportionality"}, {"option_key": "D", "hint": "Four times would occur if C ∝ A², but C is linearly proportional to A.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of capacitance is:", "explanation": "The SI unit of capacitance is the farad (F), named after Michael Faraday. One farad is defined as the capacitance when one coulomb of charge produces a potential difference of one volt, i.e., 1 F = 1 C/V.", "correct_answer": "A", "concept_tags": ["capacitance", "SI unit", "farad"], "payload": {"question_id": "cuet-phy-elec-capacitor-06", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Farad (F)", "is_correct": true}, {"key": "B", "text": "Coulomb (C)", "is_correct": false}, {"key": "C", "text": "Volt (V)", "is_correct": false}, {"key": "D", "text": "Henry (H)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Coulomb is the unit of electric charge, not capacitance. Capacitance = charge/voltage.", "misconception": "Confusing charge with capacitance"}, {"option_key": "C", "hint": "Volt is the unit of electric potential or potential difference, not capacitance.", "misconception": null}, {"option_key": "D", "hint": "Henry is the unit of inductance (used in electromagnetic induction), not capacitance.", "misconception": "Confusing capacitance with inductance"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor does NOT depend on:", "explanation": "The capacitance of a parallel plate capacitor is C = ε₀A/d (or C = κε₀A/d with a dielectric). It depends on plate area A, separation d, and the dielectric constant κ, but not on the charge stored on the plates or the potential difference applied.", "correct_answer": "D", "concept_tags": ["parallel plate capacitor", "capacitance factors", "charge independence"], "payload": {"question_id": "cuet-phy-elec-capacitor-07", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Area of the plates", "is_correct": false}, {"key": "B", "text": "Distance between the plates", "is_correct": false}, {"key": "C", "text": "Nature of the dielectric medium", "is_correct": false}, {"key": "D", "text": "Charge on the plates", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "C = ε₀A/d clearly shows capacitance is directly proportional to plate area A.", "misconception": null}, {"option_key": "B", "hint": "C = ε₀A/d shows capacitance is inversely proportional to plate separation d.", "misconception": null}, {"option_key": "C", "hint": "When a dielectric is inserted, C = κε₀A/d, showing that the dielectric constant κ affects capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor has capacitance C. If the distance between the plates is halved and a dielectric of constant K = 4 is filled in the entire space, the new capacitance is:", "explanation": "Original: C = ε₀A/d. New: d'' = d/2, K = 4. C'' = Kε₀A/d'' = 4ε₀A/(d/2) = 8ε₀A/d = 8C. Both changes (halving distance and inserting dielectric) independently multiply the capacitance.", "correct_answer": "D", "concept_tags": ["combined-effect", "dielectric-distance"], "payload": {"question_id": "cuet-phy-elec-capacitor-08", "subtopic": "Combined changes in capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2C", "is_correct": false}, {"key": "B", "text": "4C", "is_correct": false}, {"key": "C", "text": "6C", "is_correct": false}, {"key": "D", "text": "8C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2C accounts for halving the distance (×2) but ignores the dielectric (×4). Both effects multiply.", "misconception": "Considering only the distance change"}, {"option_key": "B", "hint": "4C accounts for the dielectric (×4) but ignores the halved distance (×2). The total factor is 4 × 2 = 8.", "misconception": "Considering only the dielectric effect"}, {"option_key": "C", "hint": "6C would come from adding 4 + 2 = 6, but the effects multiply (4 × 2 = 8), not add.", "misconception": "Adding individual factors instead of multiplying"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force of attraction between the plates of a parallel plate capacitor charged to voltage V with plate area A and separation d is:", "explanation": "The electric field due to one plate is E₁ = σ/(2ε₀). Force on the other plate (charge Q = σA) is F = QE₁ = σA × σ/(2ε₀) = σ²A/(2ε₀). Using σ = ε₀V/d: F = ε₀V²A/(2d²). Alternatively, F = Q²/(2ε₀A) = ε₀AV²/(2d²).", "correct_answer": "C", "concept_tags": ["force-between-plates", "attractive-force"], "payload": {"question_id": "cuet-phy-elec-capacitor-09", "subtopic": "Force on capacitor plates", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀AV²/d²", "is_correct": false}, {"key": "B", "text": "ε₀AV/d", "is_correct": false}, {"key": "C", "text": "ε₀AV²/(2d²)", "is_correct": true}, {"key": "D", "text": "ε₀AV²/(4d²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Missing the factor of ½. Each plate creates field σ/(2ε₀), not σ/ε₀ — only one plate''s field acts on the other.", "misconception": "Using the total field between plates instead of field due to one plate"}, {"option_key": "B", "hint": "This has V to the first power instead of V². Force depends on E² and E = V/d, so F ∝ V².", "misconception": "Using V instead of V²"}, {"option_key": "D", "hint": "The factor should be 1/2, not 1/4. F = σ²A/(2ε₀) = ε₀AV²/(2d²).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor is charged and disconnected from the battery. A dielectric slab of constant K is now inserted fully between the plates. Which of the following quantities increases?", "explanation": "With battery disconnected: Q = constant. Inserting dielectric: C → KC, V = Q/C → Q/(KC) = V/K (decreases), E = V/d → V/(Kd) (decreases), U = Q²/(2C) → Q²/(2KC) = U/K (decreases). Capacitance increases; V, E, and U all decrease.", "correct_answer": "A", "concept_tags": ["battery-disconnected", "dielectric-insertion", "quantity-changes"], "payload": {"question_id": "cuet-phy-elec-capacitor-10", "subtopic": "Dielectric with battery disconnected", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Capacitance", "is_correct": true}, {"key": "B", "text": "Voltage across the plates", "is_correct": false}, {"key": "C", "text": "Electric field between the plates", "is_correct": false}, {"key": "D", "text": "Energy stored", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "V = Q/C. With Q constant and C increasing (×K), V must decrease to V/K.", "misconception": "Thinking voltage stays constant without the battery"}, {"option_key": "C", "hint": "E = V/d. Since V decreases (V/K) and d is unchanged, E also decreases. The dielectric polarization opposes the original field.", "misconception": "Ignoring field reduction by dielectric polarization"}, {"option_key": "D", "hint": "U = Q²/(2C). With Q constant and C increasing, U decreases. The energy goes into pulling the slab in (work done by the force of attraction).", "misconception": "Not tracking where the lost energy goes"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two capacitors of capacitances C₁ and C₂ (C₁ > C₂) are charged to the same voltage V and then connected in parallel with like plates together. The common voltage after connection is:", "explanation": "Initial charges: Q₁ = C₁V, Q₂ = C₂V. Total charge = (C₁ + C₂)V. Total capacitance = C₁ + C₂. Common voltage V'' = (C₁ + C₂)V/(C₁ + C₂) = V. When both capacitors have the same initial voltage and are connected with like plates, no charge flows and the voltage remains V.", "correct_answer": "B", "concept_tags": ["charge-sharing", "same-voltage", "parallel-connection"], "payload": {"question_id": "cuet-phy-elec-capacitor-11", "subtopic": "Charge redistribution", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "V/2", "is_correct": false}, {"key": "B", "text": "V", "is_correct": true}, {"key": "C", "text": "2V", "is_correct": false}, {"key": "D", "text": "C₁V/(C₁ + C₂)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/2 would occur if only one capacitor were charged and the other uncharged, with equal capacitances. Here both are already at V.", "misconception": "Applying the unequal charge formula without checking initial conditions"}, {"option_key": "C", "hint": "The voltages don''t add. In parallel, the common voltage is total charge / total capacitance = V.", "misconception": "Adding voltages in parallel"}, {"option_key": "D", "hint": "This formula applies when only C₁ is charged to V and C₂ is uncharged. When both are at V, the answer simplifies to V.", "misconception": "Using the formula for one charged + one uncharged capacitor"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A dielectric slab of thickness t and dielectric constant K is placed between the plates of a parallel plate capacitor of plate separation d (t < d). The capacitance becomes:", "explanation": "The capacitor is split into two in series: air gap of (d − t) and dielectric of t. C = ε₀A / [d − t + t/K] = ε₀A / [d − t(1 − 1/K)]. This reduces to ε₀A/d when K = 1 and to ε₀A/(d − t) when K → ∞ (conductor).", "correct_answer": "D", "concept_tags": ["partial-dielectric", "series-combination", "effective-gap"], "payload": {"question_id": "cuet-phy-elec-capacitor-12", "subtopic": "Partial dielectric filling", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Kε₀A/d", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": false}, {"key": "C", "text": "Kε₀A/(d − t + Kt)", "is_correct": false}, {"key": "D", "text": "ε₀A/(d − t + t/K)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Kε₀A/d applies when the dielectric fills the entire gap. Here it fills only thickness t, leaving (d − t) as air.", "misconception": "Using the fully-filled formula for partially-filled capacitor"}, {"option_key": "B", "hint": "ε₀A/(d − t) would apply for a conducting slab (K → ∞). A dielectric with finite K doesn''t reduce the gap to (d − t).", "misconception": "Treating a dielectric slab as a conductor"}, {"option_key": "C", "hint": "Check the series formula: 1/C = (d−t)/(ε₀A) + t/(Kε₀A) = [d − t + t/K]/(ε₀A). The denominator is d − t + t/K, not d − t + Kt.", "misconception": "Multiplying by K instead of dividing by K for the dielectric region"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor has a capacitance of 10 μF. If a dielectric of dielectric constant K = 4 is inserted between the plates completely, the new capacitance becomes:", "explanation": "When a dielectric of dielectric constant K is completely inserted between the plates, the new capacitance becomes C'' = KC. Here C = 10 μF and K = 4, so C'' = 4 × 10 = 40 μF. The dielectric increases capacitance by reducing the effective electric field between the plates.", "correct_answer": "D", "concept_tags": ["dielectric", "capacitance increase", "dielectric constant"], "payload": {"question_id": "cuet-phy-elec-capacitor-13", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2.5 μF", "is_correct": false}, {"key": "B", "text": "10 μF", "is_correct": false}, {"key": "C", "text": "14 μF", "is_correct": false}, {"key": "D", "text": "40 μF", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2.5 μF = 10/4, which would result from dividing by K instead of multiplying. Dielectric increases capacitance.", "misconception": "Dividing by dielectric constant instead of multiplying"}, {"option_key": "B", "hint": "10 μF is the original capacitance. Inserting a dielectric always increases the capacitance of a parallel plate capacitor.", "misconception": "Thinking dielectric does not change capacitance"}, {"option_key": "C", "hint": "14 μF = 10 + 4, which would result from adding K to C instead of multiplying.", "misconception": "Adding dielectric constant to capacitance"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A capacitor of capacitance 6 μF is charged to a potential of 100 V. The energy stored in the capacitor is:", "explanation": "The energy stored in a capacitor is U = ½CV². Here C = 6 μF = 6 × 10⁻⁶ F and V = 100 V. So U = ½ × 6 × 10⁻⁶ × (100)² = ½ × 6 × 10⁻⁶ × 10⁴ = ½ × 6 × 10⁻² = 0.03 J = 3 × 10⁻² J.", "correct_answer": "B", "concept_tags": ["energy stored", "capacitor", "numerical calculation"], "payload": {"question_id": "cuet-phy-elec-capacitor-14", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻² J", "is_correct": false}, {"key": "B", "text": "3 × 10⁻² J", "is_correct": true}, {"key": "C", "text": "3 × 10⁻⁴ J", "is_correct": false}, {"key": "D", "text": "6 × 10⁻⁴ J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻² J results from forgetting the factor of ½ in the energy formula U = ½CV².", "misconception": "Forgetting the ½ factor in energy formula"}, {"option_key": "C", "hint": "3 × 10⁻⁴ J is 100 times too small, likely from using V = 10 V instead of V = 100 V or squaring incorrectly.", "misconception": "Error in squaring the voltage"}, {"option_key": "D", "hint": "6 × 10⁻⁴ J combines both errors: wrong power of ten and missing the ½ factor.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b05');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The capacitance of an isolated spherical conductor of radius R is:", "explanation": "For an isolated spherical conductor, the potential at its surface is V = kQ/R = Q/(4πε₀R). Since C = Q/V, we get C = Q/(Q/4πε₀R) = 4πε₀R. The capacitance of a spherical conductor depends linearly on its radius.", "correct_answer": "A", "concept_tags": ["spherical conductor", "capacitance", "isolated sphere"], "payload": {"question_id": "cuet-phy-elec-capacitor-15", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "4πε₀R", "is_correct": true}, {"key": "B", "text": "4πε₀R²", "is_correct": false}, {"key": "C", "text": "ε₀R", "is_correct": false}, {"key": "D", "text": "4πε₀/R", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4πε₀R² has an extra factor of R. Capacitance is linearly proportional to the radius, not to R².", "misconception": "Confusing area dependence with radius dependence"}, {"option_key": "C", "hint": "ε₀R is missing the 4π factor that comes from the Coulomb constant k = 1/(4πε₀).", "misconception": null}, {"option_key": "D", "hint": "4πε₀/R would make capacitance decrease with increasing radius, which contradicts the physical expectation that larger conductors have greater capacitance.", "misconception": "Inverting the radius dependence"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor with plate area A and separation d is charged to potential V. The electric field between the plates is E. If the separation is reduced to d/2 while the capacitor remains connected to the battery, the electric field becomes:", "explanation": "When the capacitor remains connected to the battery, the potential difference V across the plates stays constant. The electric field E = V/d. When separation becomes d/2, E'' = V/(d/2) = 2V/d = 2E. The electric field doubles.", "correct_answer": "C", "concept_tags": ["electric field", "parallel plate capacitor", "battery connected"], "payload": {"question_id": "cuet-phy-elec-capacitor-16", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "E/2", "is_correct": false}, {"key": "B", "text": "E", "is_correct": false}, {"key": "C", "text": "2E", "is_correct": true}, {"key": "D", "text": "4E", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "E/2 would be the result if the charge remained constant (battery disconnected) and separation was doubled, not halved.", "misconception": null}, {"option_key": "B", "hint": "The field does not remain E. With battery connected, V is constant, and since E = V/d, halving d doubles E.", "misconception": "Thinking electric field is independent of plate separation"}, {"option_key": "D", "hint": "4E would require the separation to be reduced to d/4, not d/2.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor of capacitance C is connected to a battery of EMF V. A dielectric slab of constant K is inserted. The battery remains connected. The ratio of energy stored after to before insertion is:", "explanation": "With battery connected: V = constant. Before: U₁ = ½CV². After: C'' = KC, U₂ = ½KCV². Ratio = U₂/U₁ = K. The energy increases because the battery supplies additional charge (Q₂ = KCV > Q₁ = CV), doing work. Part of this work goes to increasing U and part to pulling in the dielectric.", "correct_answer": "C", "concept_tags": ["battery-connected", "energy-ratio", "dielectric"], "payload": {"question_id": "cuet-phy-elec-capacitor-17", "subtopic": "Dielectric with battery connected", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "1/K", "is_correct": false}, {"key": "B", "text": "1/K²", "is_correct": false}, {"key": "C", "text": "K", "is_correct": true}, {"key": "D", "text": "K²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/K is the energy ratio when the battery is disconnected (U = Q²/2C, Q constant, C increases). With battery connected, V is constant, so U = ½CV² increases by K.", "misconception": "Using the battery-disconnected result for battery-connected case"}, {"option_key": "B", "hint": "1/K² has no physical basis in this scenario. With V constant and C → KC: U → ½KCV² = KU.", "misconception": null}, {"option_key": "D", "hint": "K² would arise if both C and V changed, but with the battery connected, V stays constant. Only C changes by factor K.", "misconception": "Squaring K without justification"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A spherical capacitor has inner sphere of radius a and outer sphere of radius b. Its capacitance is:", "explanation": "The potential difference between spheres: V = kQ(1/a − 1/b) = kQ(b − a)/(ab). Capacitance C = Q/V = ab/(k(b − a)) = 4πε₀ab/(b − a). When b → ∞, C → 4πε₀a (isolated sphere). When (b − a) << a, it approximates a parallel plate capacitor.", "correct_answer": "A", "concept_tags": ["spherical-capacitor", "concentric-spheres"], "payload": {"question_id": "cuet-phy-elec-capacitor-18", "subtopic": "Spherical capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "4πε₀ab/(b − a)", "is_correct": true}, {"key": "B", "text": "4πε₀(b − a)/ab", "is_correct": false}, {"key": "C", "text": "4πε₀a", "is_correct": false}, {"key": "D", "text": "4πε₀(a + b)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This inverts the fraction. C = Q/V = ab/[k(b−a)] = 4πε₀ab/(b−a), not (b−a)/ab.", "misconception": "Inverting the expression for capacitance"}, {"option_key": "C", "hint": "4πε₀a is the capacitance of an isolated sphere (outer radius → ∞). A spherical capacitor with finite b has a different formula.", "misconception": "Using isolated sphere formula for a spherical capacitor"}, {"option_key": "D", "hint": "4πε₀(a + b) doesn''t arise from the potential difference calculation. The correct formula has ab/(b − a).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor has two dielectric slabs of equal area A/2 each, placed side by side between the plates. Their dielectric constants are K₁ and K₂. The effective capacitance is:", "explanation": "Side-by-side placement means the two halves are in parallel. Each half has area A/2 and gap d. C₁ = K₁ε₀(A/2)/d, C₂ = K₂ε₀(A/2)/d. Total C = C₁ + C₂ = ε₀A(K₁ + K₂)/(2d). This is equivalent to using an effective K = (K₁ + K₂)/2.", "correct_answer": "B", "concept_tags": ["parallel-dielectrics", "side-by-side", "effective-capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-19", "subtopic": "Multiple dielectrics", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀A·K₁K₂/[d(K₁ + K₂)]", "is_correct": false}, {"key": "B", "text": "ε₀A(K₁ + K₂)/(2d)", "is_correct": true}, {"key": "C", "text": "2ε₀A(K₁ + K₂)/d", "is_correct": false}, {"key": "D", "text": "ε₀AK₁K₂/d", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the harmonic mean formula, which applies when dielectrics are stacked on top of each other (in series). Side-by-side gives the arithmetic mean.", "misconception": "Confusing series (stacked) with parallel (side-by-side) arrangement of dielectrics"}, {"option_key": "C", "hint": "The factor should be (K₁ + K₂)/2, not 2(K₁ + K₂). Each slab covers only half the area.", "misconception": "Using full area A for each half"}, {"option_key": "D", "hint": "K₁K₂ (product) is not the relevant operation. Side-by-side means parallel combination: add the individual capacitances.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "n identical capacitors, each of capacitance C, are first connected in series and then in parallel. The ratio of energy stored in the series combination to the parallel combination, when connected to the same battery of EMF V, is:", "explanation": "Series: C_s = C/n. U_s = ½(C/n)V². Parallel: C_p = nC. U_p = ½(nC)V². Ratio = U_s/U_p = (C/n)/(nC) = 1/n². The parallel combination stores n² times more energy because it has n² times the capacitance.", "correct_answer": "D", "concept_tags": ["series-parallel-energy", "ratio", "n-capacitors"], "payload": {"question_id": "cuet-phy-elec-capacitor-20", "subtopic": "Energy in combinations", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "1/n", "is_correct": false}, {"key": "B", "text": "n", "is_correct": false}, {"key": "C", "text": "n²", "is_correct": false}, {"key": "D", "text": "1/n²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/n is the capacitance ratio C_s/C_p = (C/n)/(nC) = 1/n². The energy ratio equals the capacitance ratio (since V is the same), which is 1/n², not 1/n.", "misconception": "Computing n × (1/n) instead of (1/n) × (1/n)"}, {"option_key": "B", "hint": "n would mean the series combination stores more energy, but series has smaller capacitance and therefore less energy for the same V.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "n² is the ratio U_p/U_s, not U_s/U_p. The question asks series/parallel.", "misconception": "Computing the ratio in the wrong order"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A parallel plate capacitor with a dielectric slab partially inserted is pulled inward — the dielectric slab experiences a force pulling it into the space between the plates.\nReason (R): The system tends to move toward a state of lower energy, and energy is lower with the dielectric fully inside when the battery is disconnected.", "explanation": "Both A and R are true, and R correctly explains A. When the battery is disconnected: Q is constant, and inserting the dielectric increases C, reducing U = Q²/(2C). The system seeks minimum energy, so the slab is pulled in. (When the battery is connected, U increases, but the battery does extra work — the slab is still pulled in.)", "correct_answer": "A", "concept_tags": ["dielectric-force", "energy-minimization", "slab-insertion"], "payload": {"question_id": "cuet-phy-elec-capacitor-25", "subtopic": "Force on dielectric slab", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the energy minimization principle is precisely why the force acts to pull the slab in.", "misconception": "Not seeing the causal connection between energy minimization and the force"}, {"option_key": "C", "hint": "R is correct — with battery disconnected, U = Q²/(2C). As C increases (dielectric inserted), U decreases, confirming the system moves to lower energy.", "misconception": null}, {"option_key": "D", "hint": "A is correct — this is experimentally observed. A dielectric slab is always pulled into the capacitor gap.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The capacitance of a parallel plate capacitor increases when a dielectric slab is introduced between its plates.\nReason (R): The dielectric reduces the effective electric field between the plates, thereby reducing the potential difference for the same charge.", "explanation": "Both assertion and reason are correct, and R is the correct explanation of A. The dielectric gets polarized and creates an opposing field that reduces the net electric field between the plates. Since V = Ed, the potential difference decreases for the same charge. Since C = Q/V, a decreased V for the same Q means increased C.", "correct_answer": "A", "concept_tags": ["dielectric effect", "capacitance increase", "electric field reduction"], "payload": {"question_id": "cuet-phy-elec-capacitor-26", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The reduction in electric field reduces V for the same Q, which by C = Q/V gives a higher capacitance.", "misconception": "Not seeing the causal chain: reduced E → reduced V → increased C"}, {"option_key": "C", "hint": "R is correct — the dielectric does reduce the effective electric field due to polarization of the dielectric material.", "misconception": null}, {"option_key": "D", "hint": "A is correct — it is a well-established fact that inserting a dielectric increases capacitance by a factor K.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When two capacitors charged to different voltages are connected in parallel, the total energy after connection is less than the total energy before connection.\nReason (R): Energy is lost as heat in the connecting wires due to transient current flow during charge redistribution.", "explanation": "Both A and R are true, and R correctly explains A. If C₁ at V₁ and C₂ at V₂ are connected, charge flows until voltages equalize. The energy loss ΔU = C₁C₂(V₁ − V₂)²/[2(C₁ + C₂)] > 0 whenever V₁ ≠ V₂. This energy is dissipated as Joule heating in the wires, regardless of wire resistance (lower R means faster current but same total heat).", "correct_answer": "A", "concept_tags": ["energy-loss", "charge-redistribution", "joule-heating"], "payload": {"question_id": "cuet-phy-elec-capacitor-27", "subtopic": "Energy loss in redistribution", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains A directly — the energy deficit (ΔU > 0) is accounted for exactly by the heat generated in the connecting wires.", "misconception": "Thinking the energy loss and heat are unrelated"}, {"option_key": "C", "hint": "R is correct — transient currents always flow when capacitors at different voltages are connected, and I²R heating occurs in any real wire.", "misconception": null}, {"option_key": "D", "hint": "A is correct — ΔU = C₁C₂(V₁−V₂)²/2(C₁+C₂) is always positive for V₁ ≠ V₂, confirming energy loss.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When a charged capacitor is disconnected from the battery and the plate separation is increased, the energy stored in the capacitor increases.\nReason (R): When the battery is disconnected, the charge on the capacitor plates remains constant.", "explanation": "Both A and R are correct, and R explains A. With battery disconnected, Q is constant (R is correct). Energy U = Q²/(2C). When plate separation increases, C = ε₀A/d decreases. Since Q is constant and C decreases, U = Q²/(2C) increases (A is correct). The constant charge (R) is the reason why increasing separation leads to increased energy.", "correct_answer": "A", "concept_tags": ["battery disconnected", "energy change", "plate separation"], "payload": {"question_id": "cuet-phy-elec-capacitor-28", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The fact that Q is constant (R) is precisely what determines how energy changes. With Q constant, U = Q²/(2C), so reducing C increases U.", "misconception": "Not recognizing that constant charge is the key condition determining energy behavior"}, {"option_key": "C", "hint": "R is correct — when the battery is disconnected, there is no path for charge to flow, so Q stays constant.", "misconception": null}, {"option_key": "D", "hint": "A is correct — with Q constant and C decreasing, U = Q²/(2C) must increase. The extra energy comes from the work done in pulling the plates apart against electrostatic attraction.", "misconception": "Thinking energy decreases when plates are separated"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following expressions (Column I) with the corresponding physical quantities (Column II):\n\nColumn I:\nA. C = Q/V\nB. U = ½CV²\nC. C = ε₀A/d\nD. C = 4πε₀R\n\nColumn II:\n1. Energy stored in a capacitor\n2. Capacitance of a parallel plate capacitor\n3. General definition of capacitance\n4. Capacitance of an isolated spherical conductor", "explanation": "C = Q/V is the general definition of capacitance (A→3). U = ½CV² is the energy stored in a capacitor (B→1). C = ε₀A/d is the capacitance of a parallel plate capacitor (C→2). C = 4πε₀R is the capacitance of an isolated spherical conductor (D→4).", "correct_answer": "B", "concept_tags": ["capacitance formulas", "matching", "definitions"], "payload": {"question_id": "cuet-phy-elec-capacitor-29", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-3, C-2, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-1, C-2, D-4", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 would match C = Q/V with energy, but C = Q/V is the definition of capacitance, not an energy expression.", "misconception": "Confusing definition of capacitance with energy formula"}, {"option_key": "C", "hint": "A-2 would match C = Q/V with parallel plate capacitor. While C = Q/V applies to all capacitors, ε₀A/d is specific to parallel plate geometry.", "misconception": null}, {"option_key": "D", "hint": "B-2 and C-1 are swapped. U = ½CV² is an energy expression (should match 1), not a parallel plate formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "For a parallel plate capacitor charged to voltage V and then disconnected from the battery, match the changes in Column I with the effects in Column II when plate separation is doubled:\n\nColumn I:\nA. Capacitance\nB. Charge on plates\nC. Potential difference\nD. Energy stored\n\nColumn II:\n1. Doubles\n2. Remains constant\n3. Halves\n4. Doubles", "explanation": "When battery is disconnected and d is doubled: Capacitance C = ε₀A/d halves (A→3). Charge Q remains constant as no charge can flow (B→2). Potential difference V = Q/C doubles since C halves (C→1 or C→4, both say ''Doubles''). Energy U = Q²/(2C) doubles since C halves (D→1 or D→4). The correct matching is A-3, B-2, C-1, D-4.", "correct_answer": "D", "concept_tags": ["battery disconnected", "plate separation change", "capacitor properties"], "payload": {"question_id": "cuet-phy-elec-capacitor-30", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-1, C-2, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-1, D-4", "is_correct": false}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A-1 implies capacitance doubles when separation doubles, but C = ε₀A/d shows C is inversely proportional to d, so C halves.", "misconception": "Thinking capacitance increases with plate separation"}, {"option_key": "B", "hint": "B-1 implies charge doubles, but with the battery disconnected, there is no source of additional charge. Charge must remain constant.", "misconception": "Thinking charge changes without a battery connected"}, {"option_key": "C", "hint": "A-2 implies capacitance stays the same, but changing the plate separation directly changes the capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a parallel combination of capacitors, the voltage across each capacitor is the same.", "explanation": "TRUE. In a parallel combination, both plates of each capacitor are connected to the same two nodes (same two wires). Therefore, the potential difference across each capacitor equals the potential difference between the nodes — all capacitors have the same voltage.", "correct_answer": "A", "concept_tags": ["parallel-combination", "same-voltage"], "payload": {"question_id": "cuet-phy-elec-capacitor-31", "subtopic": "Parallel combination", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In parallel, both terminals of each capacitor connect to the same nodes. By definition, voltage between two nodes is unique — so all capacitors share the same voltage.", "misconception": "Confusing parallel (same voltage) with series (same charge)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor increases when the distance between the plates is decreased.", "explanation": "This statement is TRUE. The capacitance of a parallel plate capacitor is C = ε₀A/d. Since C is inversely proportional to d (the plate separation), decreasing d increases C.", "correct_answer": "A", "concept_tags": ["parallel plate capacitor", "plate separation", "capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-32", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since C = ε₀A/d, capacitance is inversely proportional to d. Decreasing d increases C, so the statement is true.", "misconception": "Confusing direct and inverse proportionality in C = ε₀A/d"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The capacitance of a capacitor depends on the charge stored or the voltage applied across it.", "explanation": "FALSE. Capacitance C = ε₀A/d (for a parallel plate capacitor) depends only on the geometry (plate area, separation) and the medium (dielectric constant). It does NOT depend on Q or V. The ratio Q/V is always constant for a given capacitor.", "correct_answer": "B", "concept_tags": ["capacitance-independence", "geometry-dependent"], "payload": {"question_id": "cuet-phy-elec-capacitor-33", "subtopic": "Definition of capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Although C = Q/V, the capacitance is a constant for a given capacitor. Doubling Q doubles V, keeping C unchanged. Capacitance depends on geometry and medium, not on Q or V.", "misconception": "Confusing the definition C = Q/V with dependence on Q or V"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The energy stored in a capacitor is directly proportional to the square of the charge and also directly proportional to the capacitance.", "explanation": "This statement is FALSE. While U = Q²/(2C) shows energy is proportional to Q², it also shows energy is inversely proportional to C (not directly proportional). Alternatively, U = ½CV² shows energy is proportional to C only when V is constant.", "correct_answer": "B", "concept_tags": ["energy stored", "capacitor", "proportionality"], "payload": {"question_id": "cuet-phy-elec-capacitor-34", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "U = Q²/(2C) shows that for a given charge, energy is inversely proportional to capacitance, not directly proportional.", "misconception": "Confusing the different forms of the energy formula without recognizing which variables are held constant"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The energy lost when a capacitor of capacitance C charged to voltage V is connected to an identical uncharged capacitor is _____.", "explanation": "Initial energy: U₁ = ½CV². After connection: total charge = CV shared between 2C → common voltage = V/2. Final energy: U₂ = ½(2C)(V/2)² = CV²/4. Energy lost = U₁ − U₂ = CV²/2 − CV²/4 = CV²/4 = U₁/2. Exactly half the initial energy is lost as heat.", "correct_answer": "C", "concept_tags": ["energy-loss", "identical-capacitors", "half-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-35", "subtopic": "Energy loss in charge sharing", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "CV²/2", "is_correct": false}, {"key": "C", "text": "CV²/4", "is_correct": true}, {"key": "D", "text": "CV²/8", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero energy loss would violate energy conservation — the voltages are different before connection (V and 0), so current flows and energy is dissipated.", "misconception": "Thinking no energy is lost in charge redistribution"}, {"option_key": "B", "hint": "CV²/2 is the total initial energy. Not all of it is lost — half remains in the two capacitors at V/2 each.", "misconception": "Thinking all the energy is lost"}, {"option_key": "D", "hint": "CV²/8 would be the final energy in one of the capacitors, not the total energy lost.", "misconception": "Confusing the energy of one capacitor with the total energy loss"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A parallel plate capacitor has plates of area 100 cm² separated by a distance of 1 mm. The capacitance of this capacitor is _____ pF. (Take ε₀ = 8.85 × 10⁻¹² F/m)", "explanation": "C = ε₀A/d = 8.85 × 10⁻¹² × 100 × 10⁻⁴ / (1 × 10⁻³) = 8.85 × 10⁻¹² × 10⁻² / 10⁻³ = 8.85 × 10⁻¹² × 10 = 8.85 × 10⁻¹¹ F = 88.5 × 10⁻¹² F = 88.5 pF.", "correct_answer": "C", "concept_tags": ["parallel plate capacitor", "numerical calculation", "capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-36", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "8.85", "is_correct": false}, {"key": "B", "text": "885", "is_correct": false}, {"key": "C", "text": "88.5", "is_correct": true}, {"key": "D", "text": "0.885", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.85 pF would result from using A = 10 cm² or an incorrect unit conversion for the area.", "misconception": "Error in converting cm² to m²"}, {"option_key": "B", "hint": "885 pF is ten times too large, possibly from using d = 0.1 mm instead of 1 mm.", "misconception": null}, {"option_key": "D", "hint": "0.885 pF is 100 times too small, likely from a double error in unit conversion.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student connects a 10 μF capacitor to a 12 V battery and fully charges it. She then disconnects the battery and connects this charged capacitor to an identical uncharged 10 μF capacitor.\n\nThe final voltage across each capacitor and the total energy lost in the process are:", "explanation": "Initial charge Q = CV = 10 × 10⁻⁶ × 12 = 120 μC. After connecting to an identical uncharged capacitor, charge is shared equally. Common voltage V'' = Q/(C₁ + C₂) = 120/(10 + 10) = 6 V. Initial energy = ½ × 10 × 10⁻⁶ × 144 = 720 μJ. Final energy = ½ × 20 × 10⁻⁶ × 36 = 360 μJ. Energy lost = 720 − 360 = 360 μJ.", "correct_answer": "D", "concept_tags": ["charge sharing", "common potential", "energy loss"], "payload": {"question_id": "cuet-phy-elec-capacitor-37", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "12 V across each, no energy lost", "is_correct": false}, {"key": "B", "text": "6 V across each, 720 μJ lost", "is_correct": false}, {"key": "C", "text": "6 V across each, no energy lost", "is_correct": false}, {"key": "D", "text": "6 V across each, 360 μJ lost", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The voltage cannot remain 12 V because charge is shared between two capacitors. By charge conservation, the common voltage must be lower.", "misconception": "Thinking voltage remains constant during charge sharing"}, {"option_key": "B", "hint": "720 μJ is the total initial energy. Not all of it is lost — 360 μJ remains stored in the two capacitors.", "misconception": "Thinking all energy is dissipated during charge redistribution"}, {"option_key": "C", "hint": "Energy cannot be fully conserved when charge flows between capacitors at different potentials. The energy difference is dissipated as heat.", "misconception": "Ignoring energy loss during charge redistribution"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A network consists of three capacitors: C₁ = 2 μF, C₂ = 4 μF, and C₃ = 4 μF. C₁ and C₂ are in series, and their combination is in parallel with C₃. This network is connected to a 12 V battery. Calculate the total charge supplied by the battery and the voltage across C₁.", "explanation": "C₁ and C₂ in series: 1/C₁₂ = 1/2 + 1/4 = 3/4, so C₁₂ = 4/3 μF. C₁₂ in parallel with C₃: C_total = 4/3 + 4 = 16/3 μF. Total charge Q = C_total × V = (16/3) × 12 = 64 μC. For C₁₂ branch: Q₁₂ = C₁₂ × 12 = (4/3) × 12 = 16 μC. This is also Q₁ (series). Voltage across C₁: V₁ = Q₁/C₁ = 16/2 = 8 V.", "correct_answer": "B", "concept_tags": ["network", "series-parallel", "voltage-charge"], "payload": {"question_id": "cuet-phy-elec-capacitor-38", "subtopic": "Capacitor networks", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Q_total = 64 μC; V₁ = 4 V", "is_correct": false}, {"key": "B", "text": "Q_total = 64 μC; V₁ = 8 V", "is_correct": true}, {"key": "C", "text": "Q_total = 48 μC; V₁ = 8 V", "is_correct": false}, {"key": "D", "text": "Q_total = 48 μC; V₁ = 6 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q_total is correct (64 μC), but V₁ = Q₁₂/C₁ = 16/2 = 8 V, not 4 V. The 4 V is V₂ = Q₁₂/C₂ = 16/4 = 4 V (across C₂, not C₁).", "misconception": "Confusing V₁ with V₂ in the series branch"}, {"option_key": "C", "hint": "48 μC would be from C_total = 4 μF (just C₃ alone). C₁₂ = 4/3 μF adds to C₃ in parallel, giving 16/3 μF.", "misconception": "Forgetting the series combination contribution to total capacitance"}, {"option_key": "D", "hint": "Both values are incorrect. Q_total = (16/3) × 12 = 64 μC, not 48, and V₁ = 8 V, not 6 V.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b05');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for finding the equivalent capacitance of a complex capacitor network:\n\n1. Identify which capacitors are in series and which are in parallel\n2. Redraw the circuit showing simplified equivalent capacitors\n3. Check for Wheatstone bridge symmetry or balanced conditions\n4. Assign node labels and trace the current path from positive to negative terminal of the battery", "explanation": "The correct approach is: First assign nodes and trace the path (4) to understand the topology. Then check for special symmetries like Wheatstone bridge (3), which can simplify the network. Then identify series/parallel groups (1). Finally redraw with equivalents (2) and repeat if needed. Order: 4 → 3 → 1 → 2.", "correct_answer": "D", "concept_tags": ["network-analysis", "methodology", "systematic-approach"], "payload": {"question_id": "cuet-phy-elec-capacitor-39", "subtopic": "Network analysis method", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 2 → 3 → 4", "is_correct": false}, {"key": "B", "text": "1 → 3 → 4 → 2", "is_correct": false}, {"key": "C", "text": "4 → 1 → 3 → 2", "is_correct": false}, {"key": "D", "text": "4 → 3 → 1 → 2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "You can''t identify series/parallel (step 1) without first labelling nodes (step 4). Node labelling must come first to understand the topology.", "misconception": "Jumping to series/parallel identification without understanding the circuit topology"}, {"option_key": "B", "hint": "Step 4 (node labelling) must come before step 1 (series/parallel identification), not after.", "misconception": "Incorrect ordering of node identification"}, {"option_key": "C", "hint": "After labelling nodes (4), check for symmetry (3) before identifying series/parallel (1). A Wheatstone bridge eliminates one capacitor, simplifying subsequent steps.", "misconception": "Not prioritizing symmetry check before brute-force identification"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following steps in the correct order for calculating the energy stored in a charged capacitor from first principles:", "explanation": "Step 1: Start with a partially charged capacitor (charge q, voltage q/C). Step 2: Calculate the infinitesimal work to add charge dq against the existing voltage. Step 3: Integrate over the full charging process to get total energy. Step 4: Rewrite using Q = CV to get equivalent forms. This derivation shows why U = ½CV², not CV² — the voltage builds up gradually during charging.", "correct_answer": "C", "concept_tags": ["energy-derivation", "integration", "capacitor-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-40", "subtopic": "Energy stored in a capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2 → 1 → 3 → 4", "is_correct": false}, {"key": "B", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "C", "text": "1 → 2 → 3 → 4", "is_correct": true}, {"key": "D", "text": "4 → 1 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You must first set up the scenario (step 1: define the state of partial charging) before calculating the work (step 2).", "misconception": "Calculating work before defining the system state"}, {"option_key": "B", "hint": "Integration (step 3) must come after setting up the differential expression (step 2). You can''t integrate before knowing what to integrate.", "misconception": "Integrating before defining the integrand"}, {"option_key": "D", "hint": "The final expressions (step 4) are the result, not the starting point. The derivation starts from first principles.", "misconception": "Starting with the answer instead of deriving it"}]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Magnetic flux through a surface of area A placed in a uniform magnetic field B making an angle θ with the area vector is:", "explanation": "Magnetic flux is defined as Φ = B·A = BA cosθ, where θ is the angle between the magnetic field vector B and the area vector A (outward normal to the surface). This is a scalar quantity with SI unit weber (Wb). When θ = 0°, flux is maximum (Φ = BA), and when θ = 90°, flux is zero.", "correct_answer": "A", "concept_tags": ["magnetic-flux", "definition", "area-vector"], "payload": {"question_id": "cuet-phy-emi-faraday-01", "subtopic": "magnetic flux", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "BA cosθ", "is_correct": true}, {"key": "B", "value": "BA sinθ", "is_correct": false}, {"key": "C", "value": "BA tanθ", "is_correct": false}, {"key": "D", "value": "BA/cosθ", "is_correct": false}], "elimination_hints": ["Flux is calculated using the dot product of B and A, which involves cosθ, not sinθ or tanθ.", "When the field is parallel to the surface (θ = 90°), no flux passes through — only cosθ gives zero at 90°.", "BA sinθ would represent the component of B parallel to the surface, not through it."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of magnetic flux is:", "explanation": "The SI unit of magnetic flux is the weber (Wb). 1 Wb = 1 T·m² = 1 V·s. It is named after Wilhelm Eduard Weber. Magnetic flux Φ = B·A, so its unit is tesla × metre² = weber.", "correct_answer": "B", "concept_tags": ["magnetic-flux", "SI-unit", "weber"], "payload": {"question_id": "cuet-phy-emi-faraday-02", "subtopic": "magnetic flux", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "Tesla", "is_correct": false}, {"key": "B", "value": "Weber", "is_correct": true}, {"key": "C", "value": "Henry", "is_correct": false}, {"key": "D", "value": "Gauss", "is_correct": false}], "elimination_hints": ["Tesla is the unit of magnetic field strength (B), not flux.", "Henry is the unit of inductance (L), not magnetic flux.", "Gauss is the CGS unit of magnetic field, not an SI unit of flux."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Faraday''s law of electromagnetic induction, the magnitude of the induced EMF in a coil is equal to:", "explanation": "Faraday''s law states that the magnitude of induced EMF equals the rate of change of magnetic flux linkage through the coil: |ε| = |dΦ/dt|. For a coil of N turns, |ε| = N|dΦ/dt|. The negative sign in ε = −NdΦ/dt represents Lenz''s law.", "correct_answer": "C", "concept_tags": ["faraday-law", "induced-emf", "rate-of-change"], "payload": {"question_id": "cuet-phy-emi-faraday-03", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "The total magnetic flux through the coil", "is_correct": false}, {"key": "B", "value": "The product of magnetic field and area", "is_correct": false}, {"key": "C", "value": "The rate of change of magnetic flux linkage", "is_correct": true}, {"key": "D", "value": "The magnetic flux density at the centre of the coil", "is_correct": false}], "elimination_hints": ["A constant flux (no matter how large) produces zero EMF — it must be changing.", "B·A gives the flux at a moment, not the EMF. EMF requires flux to change with time.", "Magnetic flux density is just B; it is not directly equal to the induced EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The negative sign in the expression ε = −dΦ/dt represents:", "explanation": "The negative sign in Faraday''s law (ε = −dΦ/dt) represents Lenz''s law, which states that the induced EMF always opposes the change in flux that produces it. This is a consequence of the law of conservation of energy.", "correct_answer": "A", "concept_tags": ["lenz-law", "negative-sign", "flux-opposition"], "payload": {"question_id": "cuet-phy-emi-faraday-04", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Lenz''s law", "is_correct": true}, {"key": "B", "value": "Ohm''s law", "is_correct": false}, {"key": "C", "value": "Kirchhoff''s law", "is_correct": false}, {"key": "D", "value": "Ampere''s law", "is_correct": false}], "elimination_hints": ["Ohm''s law relates V, I, and R — it does not explain the direction of induced EMF.", "Kirchhoff''s laws deal with circuit analysis, not the origin of EMF direction.", "Ampere''s law relates magnetic field to current, not to the sign of induced EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Lenz''s law is a consequence of the law of conservation of:", "explanation": "Lenz''s law states that the induced current opposes the change that causes it. If the induced current aided the change, it would create a self-reinforcing cycle producing energy from nothing, violating conservation of energy. Hence Lenz''s law is a direct consequence of conservation of energy.", "correct_answer": "B", "concept_tags": ["lenz-law", "conservation-of-energy"], "payload": {"question_id": "cuet-phy-emi-faraday-05", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Charge", "is_correct": false}, {"key": "B", "value": "Energy", "is_correct": true}, {"key": "C", "value": "Momentum", "is_correct": false}, {"key": "D", "value": "Angular momentum", "is_correct": false}], "elimination_hints": ["Conservation of charge governs continuity of current, not the direction of induced EMF.", "Conservation of momentum relates to forces and motion, not electromagnetic induction.", "If the induced current aided the flux change, energy would be created from nothing — only conservation of energy prevents this."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A circular coil of 100 turns has a magnetic flux of 0.05 Wb through each turn. If the flux is reduced to zero in 0.1 s, the induced EMF is:", "explanation": "Using Faraday''s law: |ε| = N|ΔΦ/Δt| = 100 × (0.05 − 0)/0.1 = 100 × 0.5 = 50 V. The EMF is proportional to the number of turns and the rate of change of flux through each turn.", "correct_answer": "C", "concept_tags": ["faraday-law", "numerical-problem", "induced-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-06", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "5 V", "is_correct": false}, {"key": "B", "value": "10 V", "is_correct": false}, {"key": "C", "value": "50 V", "is_correct": true}, {"key": "D", "value": "500 V", "is_correct": false}], "elimination_hints": ["Don''t forget to multiply by the number of turns N = 100.", "ΔΦ = 0.05 Wb and Δt = 0.1 s, so ΔΦ/Δt = 0.5 V per turn.", "500 V would result from using Δt = 0.01 s instead of 0.1 s."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A magnet is moved towards a coil. The induced EMF does NOT depend on:", "explanation": "The induced EMF depends on the speed of the magnet (rate of flux change), the strength of the magnet (flux magnitude), and the number of turns in the coil. However, the resistance of the coil affects the induced current (I = ε/R) but not the induced EMF itself.", "correct_answer": "D", "concept_tags": ["faraday-law", "induced-emf", "resistance"], "payload": {"question_id": "cuet-phy-emi-faraday-07", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Speed of the magnet", "is_correct": false}, {"key": "B", "value": "Strength of the magnet", "is_correct": false}, {"key": "C", "value": "Number of turns in the coil", "is_correct": false}, {"key": "D", "value": "Resistance of the coil", "is_correct": true}], "elimination_hints": ["Speed of the magnet determines dΦ/dt — faster movement means larger EMF.", "A stronger magnet produces more flux, so ΔΦ is larger.", "Resistance affects current (I = ε/R), but the EMF is determined solely by the rate of flux change."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A north pole of a bar magnet is rapidly pushed into a coil. The face of the coil facing the magnet will behave as:", "explanation": "By Lenz''s law, the induced current must oppose the approaching north pole. To repel a north pole, the face of the coil facing the magnet must itself become a north pole. By the right-hand rule, this means current flows anticlockwise when viewed from the magnet''s side.", "correct_answer": "A", "concept_tags": ["lenz-law", "induced-current-direction", "bar-magnet"], "payload": {"question_id": "cuet-phy-emi-faraday-08", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "North pole and repels the magnet", "is_correct": true}, {"key": "B", "value": "South pole and attracts the magnet", "is_correct": false}, {"key": "C", "value": "South pole and repels the magnet", "is_correct": false}, {"key": "D", "value": "North pole and attracts the magnet", "is_correct": false}], "elimination_hints": ["Attracting the incoming magnet would accelerate it, increasing flux change and creating energy from nothing — violating conservation of energy.", "The coil must oppose the change, meaning it must repel the approaching north pole.", "A south pole facing the magnet would attract it, not oppose the change."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a north pole of a bar magnet is withdrawn from a coil, the face of the coil nearer to the magnet behaves as:", "explanation": "When the north pole is withdrawn, the flux through the coil decreases. By Lenz''s law, the induced current opposes this decrease by trying to maintain the flux. The face nearer to the magnet becomes a south pole to attract the receding north pole and oppose its withdrawal.", "correct_answer": "B", "concept_tags": ["lenz-law", "induced-current-direction", "bar-magnet"], "payload": {"question_id": "cuet-phy-emi-faraday-09", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "North pole", "is_correct": false}, {"key": "B", "value": "South pole", "is_correct": true}, {"key": "C", "value": "Neither north nor south pole", "is_correct": false}, {"key": "D", "value": "Alternately north and south pole", "is_correct": false}], "elimination_hints": ["A north pole would repel the receding magnet, aiding the decrease — this violates Lenz''s law.", "The coil must attract the receding magnet to oppose the decreasing flux.", "A south pole attracts a north pole, which opposes the withdrawal."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic flux through a coil varies with time as Φ = 3t² + 4t + 9 (Wb). The magnitude of the induced EMF at t = 2 s is:", "explanation": "The induced EMF is ε = −dΦ/dt. Differentiating Φ = 3t² + 4t + 9 gives dΦ/dt = 6t + 4. At t = 2 s: |ε| = |6(2) + 4| = |16| = 16 V.", "correct_answer": "B", "concept_tags": ["faraday-law", "differentiation", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-10", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "10 V", "is_correct": false}, {"key": "B", "value": "16 V", "is_correct": true}, {"key": "C", "value": "25 V", "is_correct": false}, {"key": "D", "value": "4 V", "is_correct": false}], "elimination_hints": ["You must differentiate Φ with respect to t, not just substitute t = 2 in the original expression.", "dΦ/dt = 6t + 4; substituting t = 2 gives 12 + 4 = 16 V.", "4 V would be the EMF at t = 0, not at t = 2."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A coil of 200 turns is placed in a magnetic field such that the flux through the coil changes from 0.1 Wb to 0.04 Wb in 0.02 s. The average induced EMF is:", "explanation": "Average EMF = N|ΔΦ/Δt| = 200 × |0.04 − 0.1|/0.02 = 200 × 0.06/0.02 = 200 × 3 = 600 V.", "correct_answer": "D", "concept_tags": ["faraday-law", "average-emf", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-11", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "6 V", "is_correct": false}, {"key": "B", "value": "60 V", "is_correct": false}, {"key": "C", "value": "300 V", "is_correct": false}, {"key": "D", "value": "600 V", "is_correct": true}], "elimination_hints": ["ΔΦ = |0.04 − 0.1| = 0.06 Wb, and Δt = 0.02 s.", "Don''t forget to multiply by N = 200 turns.", "6 V would be the answer if N = 2, not 200."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The total charge that flows through a coil when the flux changes is given by:", "explanation": "The charge flowed q = ∫I dt = ∫(ε/R) dt = (1/R)∫(dΦ) = NΔΦ/R. Note that the charge depends on the total change in flux and the resistance, but is independent of the time taken for the change.", "correct_answer": "A", "concept_tags": ["induced-charge", "flux-change", "resistance"], "payload": {"question_id": "cuet-phy-emi-faraday-12", "subtopic": "induced charge", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "q = NΔΦ/R", "is_correct": true}, {"key": "B", "value": "q = NΔΦ × R", "is_correct": false}, {"key": "C", "value": "q = NΔΦ/t", "is_correct": false}, {"key": "D", "value": "q = ΔΦ/(NR)", "is_correct": false}], "elimination_hints": ["Charge = ∫I dt = ∫(ε/R)dt. Since ε = NdΦ/dt, the dt cancels giving NΔΦ/R.", "Multiplying by R (option B) would give units of Wb·Ω, not coulombs.", "Charge is independent of time — it depends only on total flux change and resistance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A coil of resistance 10 Ω and 50 turns has a magnetic flux of 0.02 Wb per turn. If the flux is reversed in 0.01 s, the charge that flows through the coil is:", "explanation": "When flux is reversed, ΔΦ per turn = 0.02 − (−0.02) = 0.04 Wb. Total charge q = NΔΦ/R = 50 × 0.04/10 = 0.2 C. Note: charge depends on total flux change, not time.", "correct_answer": "B", "concept_tags": ["induced-charge", "flux-reversal", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-13", "subtopic": "induced charge", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 C", "is_correct": false}, {"key": "B", "value": "0.2 C", "is_correct": true}, {"key": "C", "value": "0.4 C", "is_correct": false}, {"key": "D", "value": "1.0 C", "is_correct": false}], "elimination_hints": ["When flux is reversed (not just reduced to zero), ΔΦ = 2 × 0.02 = 0.04 Wb.", "0.1 C results from using ΔΦ = 0.02 Wb (reducing to zero, not reversing).", "Charge is independent of the time interval (0.01 s is irrelevant here)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A conducting rod of length l moves with velocity v perpendicular to a uniform magnetic field B. The EMF induced across the rod is:", "explanation": "When a conducting rod of length l moves with velocity v perpendicular to a magnetic field B, the free electrons experience a Lorentz force F = qvB. This separates charges, creating a potential difference ε = Bvl across the rod. This is called motional EMF.", "correct_answer": "C", "concept_tags": ["motional-emf", "conducting-rod", "lorentz-force"], "payload": {"question_id": "cuet-phy-emi-faraday-14", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "Bl/v", "is_correct": false}, {"key": "B", "value": "Bv/l", "is_correct": false}, {"key": "C", "value": "Bvl", "is_correct": true}, {"key": "D", "value": "Bl²v", "is_correct": false}], "elimination_hints": ["The force on each electron is qvB, and the potential builds up over the length l, giving ε = Bvl.", "Bl/v has units of T·m/(m/s) = T·s, which is not volts.", "Bv/l has units of T·m/s·m⁻¹ = T/s, which is not volts either."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A metallic rod of length 1 m moves at 5 m/s perpendicular to a magnetic field of 0.4 T. The EMF developed across the rod is:", "explanation": "Motional EMF ε = Bvl = 0.4 × 5 × 1 = 2 V. The rod cuts magnetic field lines as it moves, and the Lorentz force on free electrons creates a potential difference across its ends.", "correct_answer": "B", "concept_tags": ["motional-emf", "numerical-problem", "conducting-rod"], "payload": {"question_id": "cuet-phy-emi-faraday-15", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.2 V", "is_correct": false}, {"key": "B", "value": "2 V", "is_correct": true}, {"key": "C", "value": "20 V", "is_correct": false}, {"key": "D", "value": "0.4 V", "is_correct": false}], "elimination_hints": ["ε = Bvl = 0.4 × 5 × 1. Simply multiply the three values.", "0.2 V would result from using v = 0.5 m/s instead of 5 m/s.", "0.4 V is just the value of B, not the EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A rod moves parallel to a uniform magnetic field. The EMF induced in the rod is:", "explanation": "When a rod moves parallel to the magnetic field, v is parallel to B. The Lorentz force on electrons F = qv × B = 0 (since sin0° = 0). No charge separation occurs, so no EMF is induced. EMF is induced only when the velocity has a component perpendicular to B.", "correct_answer": "A", "concept_tags": ["motional-emf", "parallel-motion", "zero-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-16", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "Bvl", "is_correct": false}, {"key": "C", "value": "Bvl/2", "is_correct": false}, {"key": "D", "value": "2Bvl", "is_correct": false}], "elimination_hints": ["The cross product v × B = 0 when v is parallel to B (sin0° = 0).", "For EMF to be induced, the rod must cut magnetic field lines — parallel motion doesn''t cut any.", "Bvl applies only when v is perpendicular to both B and the rod."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A metallic rod of length l is rotated about one end with angular velocity ω in a uniform magnetic field B perpendicular to the plane of rotation. The EMF induced between the ends of the rod is:", "explanation": "Consider a small element dx at distance x from the pivot. Its velocity is v = ωx. The EMF across this element is dε = Bvdx = Bωx dx. Integrating from 0 to l: ε = Bω∫₀ˡ x dx = Bωl²/2 = (1/2)Bωl².", "correct_answer": "C", "concept_tags": ["rotating-rod", "motional-emf", "integration"], "payload": {"question_id": "cuet-phy-emi-faraday-17", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "Bωl", "is_correct": false}, {"key": "B", "value": "Bωl²", "is_correct": false}, {"key": "C", "value": "(1/2)Bωl²", "is_correct": true}, {"key": "D", "value": "2Bωl²", "is_correct": false}], "elimination_hints": ["Each element at distance x has velocity ωx, not ωl — you must integrate.", "Integration of x from 0 to l gives l²/2, hence the factor of 1/2.", "Bωl² would be the answer if every part of the rod moved at speed ωl."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A metallic rod of length 0.5 m is rotated about one end at 2 rev/s in a perpendicular magnetic field of 0.1 T. The EMF induced between the ends is approximately:", "explanation": "ω = 2πf = 2π × 2 = 4π rad/s. EMF = (1/2)Bωl² = (1/2) × 0.1 × 4π × (0.5)² = (1/2) × 0.1 × 4π × 0.25 = 0.05π ≈ 0.157 V ≈ 0.16 V.", "correct_answer": "B", "concept_tags": ["rotating-rod", "numerical-problem", "rpm-conversion"], "payload": {"question_id": "cuet-phy-emi-faraday-18", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.05 V", "is_correct": false}, {"key": "B", "value": "0.16 V", "is_correct": true}, {"key": "C", "value": "0.50 V", "is_correct": false}, {"key": "D", "value": "1.57 V", "is_correct": false}], "elimination_hints": ["Convert rev/s to rad/s: ω = 2π × 2 = 4π rad/s.", "Use ε = (1/2)Bωl² = (1/2)(0.1)(4π)(0.25) = 0.05π ≈ 0.157 V.", "1.57 V results from forgetting the factor of 1/2 and using l instead of l²."]}}]'::jsonb, 'deploy-2026-03-05-b05');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A rectangular coil of area A having N turns is rotated at f revolutions per second in a uniform magnetic field B. The maximum value of the induced EMF is:", "explanation": "When a coil rotates in a magnetic field, Φ = NBA cos(ωt) = NBA cos(2πft). The induced EMF ε = −dΦ/dt = NBA(2πf)sin(2πft). The maximum value of EMF is ε₀ = NBA(2πf) = 2πfNBA.", "correct_answer": "D", "concept_tags": ["ac-generator", "peak-emf", "rotating-coil"], "payload": {"question_id": "cuet-phy-emi-faraday-19", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "NBAf", "is_correct": false}, {"key": "B", "value": "NBA/f", "is_correct": false}, {"key": "C", "value": "πfNBA", "is_correct": false}, {"key": "D", "value": "2πfNBA", "is_correct": true}], "elimination_hints": ["Differentiating cos(2πft) gives a factor of 2πf, not just f.", "NBAf is missing the 2π factor from the angular frequency.", "πfNBA is off by a factor of 2 — ω = 2πf, not πf."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC generator, the EMF is maximum when the plane of the coil is:", "explanation": "The flux Φ = BA cosθ where θ is the angle between B and the area vector. EMF = −dΦ/dt is maximum when dΦ/dt is maximum, which occurs when cos(θ) is changing most rapidly, i.e., when θ = 90°. At this position, the plane of the coil is parallel to the magnetic field and the flux through it is zero.", "correct_answer": "A", "concept_tags": ["ac-generator", "peak-emf", "coil-orientation"], "payload": {"question_id": "cuet-phy-emi-faraday-20", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Parallel to the magnetic field", "is_correct": true}, {"key": "B", "value": "Perpendicular to the magnetic field", "is_correct": false}, {"key": "C", "value": "At 45° to the magnetic field", "is_correct": false}, {"key": "D", "value": "At 60° to the magnetic field", "is_correct": false}], "elimination_hints": ["When the coil is perpendicular to B, flux is maximum but its rate of change is zero — so EMF is zero.", "EMF is maximum where flux is changing fastest, which is where flux passes through zero.", "Flux is zero when the plane of the coil is parallel to B, and this is where dΦ/dt is maximum."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An EMF is induced in a coil when:", "explanation": "An EMF is induced in a coil only when the magnetic flux through it changes with time (Faraday''s law). A steady magnetic field or constant flux, no matter how strong, does not induce any EMF.", "correct_answer": "C", "concept_tags": ["faraday-law", "flux-change", "induced-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-21", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "It is placed in a strong magnetic field", "is_correct": false}, {"key": "B", "value": "A steady current flows through it", "is_correct": false}, {"key": "C", "value": "The magnetic flux linked with it changes", "is_correct": true}, {"key": "D", "value": "It is placed in a uniform magnetic field", "is_correct": false}], "elimination_hints": ["A strong but constant field produces zero EMF — the field must be changing.", "A steady current creates a constant magnetic field, which doesn''t induce EMF in the same coil.", "Uniform field is also constant; uniform just means same everywhere, not changing."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic flux through a coil of 10 turns changes from 0.5 Wb to 0.1 Wb in 0.1 s. If the resistance of the coil is 2 Ω, the induced current is:", "explanation": "EMF = N|ΔΦ/Δt| = 10 × |0.1 − 0.5|/0.1 = 10 × 4 = 40 V. Current I = EMF/R = 40/2 = 20 A.", "correct_answer": "C", "concept_tags": ["faraday-law", "induced-current", "ohm-law"], "payload": {"question_id": "cuet-phy-emi-faraday-22", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "2 A", "is_correct": false}, {"key": "B", "value": "10 A", "is_correct": false}, {"key": "C", "value": "20 A", "is_correct": true}, {"key": "D", "value": "40 A", "is_correct": false}], "elimination_hints": ["First find EMF: N × ΔΦ/Δt = 10 × 0.4/0.1 = 40 V.", "Then use Ohm''s law: I = EMF/R = 40/2 = 20 A.", "40 A would be the answer if R = 1 Ω."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The magnetic field in a region is given by B = B₀(t/τ), where B₀ and τ are constants. A conducting ring of radius r placed perpendicular to the field has resistance R. The induced current in the ring is:", "explanation": "Flux Φ = BA = B₀(t/τ) × πr². EMF = dΦ/dt = B₀πr²/τ (constant). Current I = EMF/R = πr²B₀/(τR). The current is constant because B increases linearly with time.", "correct_answer": "A", "concept_tags": ["faraday-law", "time-varying-field", "induced-current"], "payload": {"question_id": "cuet-phy-emi-faraday-23", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "πr²B₀/(τR)", "is_correct": true}, {"key": "B", "value": "πr²B₀τ/R", "is_correct": false}, {"key": "C", "value": "πr²B₀/(τR²)", "is_correct": false}, {"key": "D", "value": "2πrB₀/(τR)", "is_correct": false}], "elimination_hints": ["Area of the ring is πr², not 2πr (which is the circumference).", "Differentiating t/τ with respect to t gives 1/τ, so τ appears in the denominator.", "R appears in the denominator through Ohm''s law (I = EMF/R), not as R²."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A conducting rod slides along two parallel conducting rails at constant velocity v in a uniform magnetic field B directed into the page. As the rod moves, the motional EMF will:", "explanation": "The motional EMF ε = Bvl remains constant because B, v, and l are all constant. However, the current I = ε/R decreases if the resistance of the circuit increases (due to increasing rail length), or remains constant if the rail resistance is negligible compared to a fixed external resistance.", "correct_answer": "B", "concept_tags": ["motional-emf", "conducting-rod", "constant-velocity"], "payload": {"question_id": "cuet-phy-emi-faraday-24", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Increase with time", "is_correct": false}, {"key": "B", "value": "Remain constant", "is_correct": true}, {"key": "C", "value": "Decrease with time", "is_correct": false}, {"key": "D", "value": "First increase then decrease", "is_correct": false}], "elimination_hints": ["EMF = Bvl — none of these quantities change with time if v is constant.", "Don''t confuse EMF with current. Current may change if resistance changes, but EMF stays constant.", "The area swept per unit time is constant (v × l), so dΦ/dt = Bvl is constant."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wheel with 10 metallic spokes each 0.5 m long is rotated at 120 rpm in a magnetic field of 0.4 T perpendicular to the plane of the wheel. The EMF induced between the axle and the rim of the wheel is:", "explanation": "Each spoke acts as a rod rotating about one end. ω = 2π × 120/60 = 4π rad/s. EMF per spoke = (1/2)Bωl² = (1/2)(0.4)(4π)(0.25) = 0.2π ≈ 0.628 V. All spokes are in parallel between axle and rim, so the net EMF equals the EMF of one spoke ≈ 0.628 V.", "correct_answer": "C", "concept_tags": ["rotating-rod", "spoked-wheel", "parallel-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-25", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "6.28 V", "is_correct": false}, {"key": "B", "value": "3.14 V", "is_correct": false}, {"key": "C", "value": "0.628 V", "is_correct": true}, {"key": "D", "value": "62.8 V", "is_correct": false}], "elimination_hints": ["All spokes are in parallel — the EMF is that of one spoke, not the sum.", "ω = 2π × 2 = 4π rad/s (120 rpm = 2 rps).", "6.28 V would result from multiplying by the number of spokes, which is incorrect for parallel connections."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A rectangular loop of sides 10 cm and 5 cm is moved out of a uniform magnetic field of 0.5 T at a speed of 2 m/s. The EMF induced while the loop is partly inside the field is:", "explanation": "As the loop moves out, the area inside the field decreases. The rate of area change = l × v where l is the side perpendicular to the velocity. Here l = 5 cm = 0.05 m. EMF = Blv = 0.5 × 0.05 × 2 = 0.05 V = 50 mV.", "correct_answer": "B", "concept_tags": ["motional-emf", "rectangular-loop", "flux-change"], "payload": {"question_id": "cuet-phy-emi-faraday-26", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "100 mV", "is_correct": false}, {"key": "B", "value": "50 mV", "is_correct": true}, {"key": "C", "value": "25 mV", "is_correct": false}, {"key": "D", "value": "10 mV", "is_correct": false}], "elimination_hints": ["Use the side perpendicular to the direction of motion (5 cm = 0.05 m).", "100 mV would result from using 10 cm (0.1 m) as the effective length.", "EMF = Blv = 0.5 × 0.05 × 2 = 0.05 V = 50 mV."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a rectangular loop is completely inside a uniform magnetic field and moves with constant velocity, the induced EMF is:", "explanation": "When a loop is completely inside a uniform field, the flux through it remains constant as it moves (the field is the same everywhere). Since dΦ/dt = 0, the induced EMF is zero. EMF is induced only when the loop is entering or leaving the field region.", "correct_answer": "A", "concept_tags": ["uniform-field", "zero-emf", "rectangular-loop"], "payload": {"question_id": "cuet-phy-emi-faraday-27", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "Bvl", "is_correct": false}, {"key": "C", "value": "2Bvl", "is_correct": false}, {"key": "D", "value": "Bvl/2", "is_correct": false}], "elimination_hints": ["Both leading and trailing edges cut field lines, but their EMFs cancel out.", "The total flux doesn''t change if the field is uniform and the entire loop is inside.", "EMF ≠ 0 only when the loop is partially inside the field (entering or leaving)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The magnetic flux through a coil perpendicular to its plane is given by Φ = 5t³ − 4t² + t (Wb). The induced EMF at t = 1 s is:", "explanation": "ε = −dΦ/dt = −(15t² − 8t + 1). At t = 1: ε = −(15 − 8 + 1) = −8 V. The magnitude of the induced EMF is 8 V.", "correct_answer": "C", "concept_tags": ["faraday-law", "differentiation", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-28", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "2 V", "is_correct": false}, {"key": "B", "value": "6 V", "is_correct": false}, {"key": "C", "value": "8 V", "is_correct": true}, {"key": "D", "value": "15 V", "is_correct": false}], "elimination_hints": ["Differentiate: dΦ/dt = 15t² − 8t + 1. At t = 1: 15 − 8 + 1 = 8.", "Don''t substitute t = 1 in Φ directly — you must differentiate first.", "2 V would be the answer for Φ at t = 1, not the EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following does NOT cause electromagnetic induction?", "explanation": "Electromagnetic induction requires a change in magnetic flux through a coil. A coil stationary in a constant uniform magnetic field has constant flux, so no EMF is induced. Moving a magnet, changing current in a nearby coil, or rotating a coil in a field all cause flux changes.", "correct_answer": "D", "concept_tags": ["faraday-law", "flux-change", "conceptual"], "payload": {"question_id": "cuet-phy-emi-faraday-29", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Moving a magnet towards a coil", "is_correct": false}, {"key": "B", "value": "Changing the current in a nearby coil", "is_correct": false}, {"key": "C", "value": "Rotating a coil in a magnetic field", "is_correct": false}, {"key": "D", "value": "Placing a coil in a steady uniform magnetic field", "is_correct": true}], "elimination_hints": ["A moving magnet changes the flux through the coil — induction occurs.", "Changing current changes the magnetic field, hence flux — induction occurs.", "A steady field means constant flux, so dΦ/dt = 0 and no EMF is induced."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coil of area 0.04 m² and 100 turns is placed in a magnetic field of 0.2 T. If the coil is rotated through 180° in 0.1 s, the average induced EMF is:", "explanation": "Initial flux per turn Φ₁ = BA = 0.2 × 0.04 = 0.008 Wb. After 180° rotation, Φ₂ = −BA = −0.008 Wb. ΔΦ = Φ₂ − Φ₁ = −0.016 Wb. Average EMF = N|ΔΦ/Δt| = 100 × 0.016/0.1 = 16 V.", "correct_answer": "D", "concept_tags": ["faraday-law", "coil-rotation", "average-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-30", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.8 V", "is_correct": false}, {"key": "B", "value": "4 V", "is_correct": false}, {"key": "C", "value": "8 V", "is_correct": false}, {"key": "D", "value": "16 V", "is_correct": true}], "elimination_hints": ["A 180° rotation reverses the flux: ΔΦ = 2BA, not just BA.", "8 V would result from using ΔΦ = BA instead of 2BA.", "Remember: N = 100 turns, and each turn contributes to the total EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular coil of radius r is placed in a time-varying magnetic field B = B₀ sin(ωt). The maximum induced EMF in the coil is:", "explanation": "Flux Φ = BA = B₀ sin(ωt) × πr². EMF = −dΦ/dt = −B₀πr²ω cos(ωt). Maximum EMF = B₀πr²ω.", "correct_answer": "B", "concept_tags": ["faraday-law", "sinusoidal-field", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-31", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "B₀πr²", "is_correct": false}, {"key": "B", "value": "B₀πr²ω", "is_correct": true}, {"key": "C", "value": "B₀πr²/ω", "is_correct": false}, {"key": "D", "value": "B₀r²ω", "is_correct": false}], "elimination_hints": ["Differentiating sin(ωt) gives ω cos(ωt), so a factor of ω appears.", "B₀πr² is just the maximum flux, not the maximum EMF.", "B₀r²ω is missing the factor of π from the area of the circle (A = πr²)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Faraday''s laws of electromagnetic induction are related to:", "explanation": "Faraday''s laws describe how a changing magnetic flux produces an induced EMF (and hence current in a closed circuit). This is the principle of conservation of energy applied to electromagnetic phenomena. The laws are fundamental to generators, transformers, and inductors.", "correct_answer": "C", "concept_tags": ["faraday-law", "conservation-of-energy"], "payload": {"question_id": "cuet-phy-emi-faraday-32", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "Law of conservation of charge only", "is_correct": false}, {"key": "B", "value": "Interaction between electric charges", "is_correct": false}, {"key": "C", "value": "Conservation of energy", "is_correct": true}, {"key": "D", "value": "Conservation of linear momentum", "is_correct": false}], "elimination_hints": ["Faraday''s laws, together with Lenz''s law, ensure energy conservation in electromagnetic induction.", "Interaction between charges is described by Coulomb''s law, not Faraday''s law.", "Conservation of momentum governs collisions and forces, not electromagnetic induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A copper ring is held horizontally and a bar magnet is dropped through the ring with its length along the axis of the ring. The acceleration of the falling magnet is:", "explanation": "As the magnet falls through the ring, the changing flux induces a current in the ring (Lenz''s law). This current creates a magnetic field that opposes the magnet''s motion, exerting a retarding force. So the net downward force is less than mg, and the acceleration is less than g.", "correct_answer": "B", "concept_tags": ["lenz-law", "falling-magnet", "retarding-force"], "payload": {"question_id": "cuet-phy-emi-faraday-33", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "Equal to g", "is_correct": false}, {"key": "B", "value": "Less than g", "is_correct": true}, {"key": "C", "value": "Greater than g", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": false}], "elimination_hints": ["If the ring were non-conducting (no current), the magnet would fall with acceleration g.", "Lenz''s law causes opposition, which decelerates the magnet, making a < g.", "The magnet does not stop (a ≠ 0) — it just falls slower than free fall."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two identical bar magnets are dropped simultaneously through two identical metallic rings — one made of copper and the other with a narrow cut (broken ring). Which magnet reaches the ground first?", "explanation": "The magnet through the broken ring reaches the ground first. The broken ring cannot sustain a continuous current (the gap prevents it), so there is no opposing force on the magnet. The magnet through the intact copper ring experiences a retarding force due to induced eddy currents (Lenz''s law) and falls slower.", "correct_answer": "B", "concept_tags": ["lenz-law", "broken-ring", "eddy-currents"], "payload": {"question_id": "cuet-phy-emi-faraday-34", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "analyze", "options": [{"key": "A", "value": "The magnet through the copper ring", "is_correct": false}, {"key": "B", "value": "The magnet through the broken ring", "is_correct": true}, {"key": "C", "value": "Both reach at the same time", "is_correct": false}, {"key": "D", "value": "Neither reaches the ground", "is_correct": false}], "elimination_hints": ["A broken ring cannot sustain eddy currents — there''s no complete conducting path.", "Without current, there''s no magnetic opposition, so the magnet falls freely.", "The intact ring opposes the magnet''s motion (Lenz''s law), slowing it down."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A coil of 500 turns is placed in a magnetic field. The flux through the coil changes at a steady rate from 2 × 10⁻³ Wb to 8 × 10⁻³ Wb in 5 s. The induced EMF in the coil is:", "explanation": "EMF = N|ΔΦ/Δt| = 500 × |8 × 10⁻³ − 2 × 10⁻³|/5 = 500 × 6 × 10⁻³/5 = 500 × 1.2 × 10⁻³ = 0.6 V.", "correct_answer": "B", "concept_tags": ["faraday-law", "numerical-problem", "average-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-35", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.3 V", "is_correct": false}, {"key": "B", "value": "0.6 V", "is_correct": true}, {"key": "C", "value": "1.2 V", "is_correct": false}, {"key": "D", "value": "3.0 V", "is_correct": false}], "elimination_hints": ["ΔΦ = (8 − 2) × 10⁻³ = 6 × 10⁻³ Wb.", "ΔΦ/Δt = 6 × 10⁻³/5 = 1.2 × 10⁻³ V per turn.", "Multiply by N = 500: EMF = 500 × 1.2 × 10⁻³ = 0.6 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A conducting rod PQ of length l is moving with velocity v in a uniform magnetic field B directed into the page. The end P of the rod is at higher potential if:", "explanation": "Using the Lorentz force F = qv × B on positive charges in the rod: if the rod moves to the right and B is into the page, the force on positive charges is from Q to P (upward). So positive charges accumulate at P, making P at higher potential. This follows from the right-hand rule or F = qv × B.", "correct_answer": "A", "concept_tags": ["motional-emf", "lorentz-force", "potential-difference"], "payload": {"question_id": "cuet-phy-emi-faraday-36", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "analyze", "options": [{"key": "A", "value": "The rod moves to the right with P at the top", "is_correct": true}, {"key": "B", "value": "The rod moves to the left with P at the top", "is_correct": false}, {"key": "C", "value": "The rod moves upward", "is_correct": false}, {"key": "D", "value": "The rod is stationary", "is_correct": false}], "elimination_hints": ["If the rod is stationary, there is no motional EMF — no potential difference.", "Use F = qv × B to determine the direction of force on positive charges.", "Reversing the direction of v reverses the force direction and hence which end is at higher potential."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC generator produces an EMF ε = 200 sin(100πt) V. The maximum EMF and frequency of the generator are:", "explanation": "Comparing with ε = ε₀ sin(ωt): ε₀ = 200 V and ω = 100π rad/s. Frequency f = ω/(2π) = 100π/(2π) = 50 Hz.", "correct_answer": "C", "concept_tags": ["ac-generator", "peak-emf", "frequency"], "payload": {"question_id": "cuet-phy-emi-faraday-37", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "200 V, 100 Hz", "is_correct": false}, {"key": "B", "value": "100 V, 50 Hz", "is_correct": false}, {"key": "C", "value": "200 V, 50 Hz", "is_correct": true}, {"key": "D", "value": "200 V, 100π Hz", "is_correct": false}], "elimination_hints": ["The coefficient of sin gives ε₀ = 200 V directly.", "ω = 100π rad/s; frequency f = ω/(2π) = 50 Hz, not 100 Hz.", "100π Hz would mean ω = 2π × 100π = 200π² rad/s, which is incorrect."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coil of 50 turns and area 800 cm² is rotating at 60 rpm about an axis perpendicular to a field of 0.05 T. The maximum EMF induced in the coil is approximately:", "explanation": "ε₀ = NBAω. N = 50, B = 0.05 T, A = 800 cm² = 0.08 m², ω = 2π × 60/60 = 2π rad/s. ε₀ = 50 × 0.05 × 0.08 × 2π = 50 × 0.004 × 2π = 0.2 × 2π = 0.4π ≈ 1.26 V.", "correct_answer": "B", "concept_tags": ["ac-generator", "numerical-problem", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-38", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.4 V", "is_correct": false}, {"key": "B", "value": "1.26 V", "is_correct": true}, {"key": "C", "value": "4.0 V", "is_correct": false}, {"key": "D", "value": "12.6 V", "is_correct": false}], "elimination_hints": ["Convert area: 800 cm² = 800 × 10⁻⁴ m² = 0.08 m².", "Convert rpm to rad/s: 60 rpm = 1 rps = 2π rad/s.", "0.4 V is the value without the 2π factor from ω."]}}]'::jsonb, 'deploy-2026-03-05-b05');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC generator, the EMF is zero when the angle between the plane of the coil and the magnetic field is:", "explanation": "EMF = NBAω sin(θ), where θ is the angle between the area vector (normal to the coil plane) and B. EMF = 0 when sin(θ) = 0, i.e., θ = 0° or 180°. At θ = 0°, the plane of the coil is perpendicular to B (area vector parallel to B), and flux is maximum.", "correct_answer": "B", "concept_tags": ["ac-generator", "zero-emf", "coil-orientation"], "payload": {"question_id": "cuet-phy-emi-faraday-39", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "0°", "is_correct": false}, {"key": "B", "value": "90°", "is_correct": true}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "30°", "is_correct": false}], "elimination_hints": ["EMF ∝ sin(θ) where θ is between area vector and B. When the plane of the coil is perpendicular to B, the angle between the plane and B is 90° and the area vector is parallel to B (θ = 0°), giving sin(0°) = 0.", "When the plane of the coil makes 90° with B, the area vector is parallel to B, giving maximum flux but zero rate of change.", "The EMF is zero when flux is at its maximum or minimum value."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A square coil of side 10 cm and 20 turns is rotated about its vertical diagonal in a horizontal magnetic field of 0.5 T. If the angular speed of rotation is 300 rad/s, the maximum EMF induced is:", "explanation": "For a square coil rotating about its diagonal, the effective area swept by each half is the full area of the square. A = (0.1)² = 0.01 m². ε₀ = NBAω = 20 × 0.5 × 0.01 × 300 = 30 V.", "correct_answer": "C", "concept_tags": ["ac-generator", "rotating-coil", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-40", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "15 V", "is_correct": false}, {"key": "B", "value": "20 V", "is_correct": false}, {"key": "C", "value": "30 V", "is_correct": true}, {"key": "D", "value": "60 V", "is_correct": false}], "elimination_hints": ["Area of the square = (0.1)² = 0.01 m². Use the full area, not half.", "ε₀ = NBAω = 20 × 0.5 × 0.01 × 300 = 30 V.", "15 V would result from using half the area (0.005 m²)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Self-inductance of a coil is defined as:", "explanation": "Self-inductance L is the ratio of total magnetic flux linkage (NΦ) to the current I flowing through the coil: L = NΦ/I. It measures a coil''s ability to oppose changes in current through it by inducing a back-EMF. The SI unit of self-inductance is henry (H).", "correct_answer": "B", "concept_tags": ["self-inductance", "definition", "flux-linkage"], "payload": {"question_id": "cuet-phy-emi-inductance-01", "subtopic": "self-inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L = Φ/NI", "is_correct": false}, {"key": "B", "value": "L = NΦ/I", "is_correct": true}, {"key": "C", "value": "L = NI/Φ", "is_correct": false}, {"key": "D", "value": "L = I/NΦ", "is_correct": false}], "elimination_hints": ["L has units of Wb/A = henry. NΦ/I gives Wb/A, which is correct.", "NI/Φ has units of A/Wb — the inverse of henry.", "Φ/NI gives Wb/A but divides by N unnecessarily — flux linkage is NΦ, not Φ/N."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of self-inductance is:", "explanation": "The SI unit of self-inductance is henry (H), named after Joseph Henry. 1 H = 1 Wb/A = 1 V·s/A = 1 kg·m²·s⁻²·A⁻². A coil has an inductance of 1 henry if a current of 1 A produces a flux linkage of 1 Wb through it.", "correct_answer": "A", "concept_tags": ["self-inductance", "SI-unit", "henry"], "payload": {"question_id": "cuet-phy-emi-inductance-02", "subtopic": "self-inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Henry (H)", "is_correct": true}, {"key": "B", "value": "Weber (Wb)", "is_correct": false}, {"key": "C", "value": "Tesla (T)", "is_correct": false}, {"key": "D", "value": "Farad (F)", "is_correct": false}], "elimination_hints": ["Weber is the unit of magnetic flux, not inductance.", "Tesla is the unit of magnetic field strength.", "Farad is the unit of capacitance, not inductance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The self-induced EMF in a coil is given by:", "explanation": "When current through an inductor changes, the self-induced EMF (back-EMF) is ε = −L(dI/dt). The negative sign indicates the EMF opposes the change in current (Lenz''s law). L is the self-inductance of the coil.", "correct_answer": "C", "concept_tags": ["self-inductance", "back-emf", "rate-of-change"], "payload": {"question_id": "cuet-phy-emi-inductance-03", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "ε = LI", "is_correct": false}, {"key": "B", "value": "ε = L/I", "is_correct": false}, {"key": "C", "value": "ε = −L(dI/dt)", "is_correct": true}, {"key": "D", "value": "ε = −LI²/2", "is_correct": false}], "elimination_hints": ["LI has units of H·A = Wb, which is flux, not EMF (volts).", "LI²/2 has units of H·A² = joules — that''s the energy stored in an inductor.", "The EMF must involve rate of change of current, not just current itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The self-inductance of a long solenoid of length l, total number of turns N, and cross-sectional area A is:", "explanation": "For a solenoid with n = N/l turns per unit length, B = μ₀nI. Flux through each turn = BA = μ₀nIA. Total flux linkage = NΦ = N × μ₀nIA = μ₀N²IA/l. So L = NΦ/I = μ₀N²A/l.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-04", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "μ₀NA/l", "is_correct": false}, {"key": "B", "value": "μ₀N²A/l", "is_correct": true}, {"key": "C", "value": "μ₀N²l/A", "is_correct": false}, {"key": "D", "value": "μ₀NA²/l", "is_correct": false}], "elimination_hints": ["L depends on N² because both the flux (∝ N) and the linkage (× N) involve N.", "Increasing length l (keeping N constant) reduces n = N/l, weakening B, so l is in the denominator.", "Increasing area A increases flux through each turn, so A is in the numerator."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the number of turns in a solenoid is doubled (keeping length and area the same), the self-inductance becomes:", "explanation": "L = μ₀N²A/l. If N is doubled to 2N, L'' = μ₀(2N)²A/l = 4μ₀N²A/l = 4L. Self-inductance is proportional to N², so doubling N quadruples L.", "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "proportionality"], "payload": {"question_id": "cuet-phy-emi-inductance-05", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "Doubled", "is_correct": false}, {"key": "B", "value": "Halved", "is_correct": false}, {"key": "C", "value": "Four times", "is_correct": true}, {"key": "D", "value": "Unchanged", "is_correct": false}], "elimination_hints": ["L ∝ N². Doubling N means L ∝ (2N)² = 4N².", "If L were proportional to N (not N²), doubling N would double L.", "The N² dependence arises because both B (∝ N) and flux linkage (× N) depend on N."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of 1000 turns, length 50 cm, and cross-sectional area 10 cm² is wound on a non-magnetic material. Its self-inductance is approximately:", "explanation": "L = μ₀N²A/l = 4π × 10⁻⁷ × (1000)² × 10 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 10⁶ × 10⁻³ / 0.5 = 4π × 10⁻⁴ / 0.5 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ H ≈ 2.5 mH.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-06", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "0.25 mH", "is_correct": false}, {"key": "B", "value": "2.5 mH", "is_correct": true}, {"key": "C", "value": "25 mH", "is_correct": false}, {"key": "D", "value": "0.5 mH", "is_correct": false}], "elimination_hints": ["Convert units: l = 0.5 m, A = 10 × 10⁻⁴ = 10⁻³ m².", "L = 4π × 10⁻⁷ × 10⁶ × 10⁻³ / 0.5 = 8π × 10⁻⁴ ≈ 2.5 × 10⁻³ H.", "0.25 mH would be 10 times too small — likely a unit conversion error."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The self-inductance of a solenoid depends on:", "explanation": "L = μ₀N²A/l depends on geometry (N, A, l) and the medium (μ₀ or μ). It does NOT depend on the current flowing through the solenoid. Inductance is a property of the coil itself, not of the current.", "correct_answer": "D", "concept_tags": ["self-inductance", "factors", "geometry"], "payload": {"question_id": "cuet-phy-emi-inductance-07", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "The current through the solenoid", "is_correct": false}, {"key": "B", "value": "The voltage across the solenoid", "is_correct": false}, {"key": "C", "value": "The resistance of the wire", "is_correct": false}, {"key": "D", "value": "The number of turns, area, and length", "is_correct": true}], "elimination_hints": ["L = μ₀N²A/l — there is no I or V in this formula.", "Current determines the magnetic field strength, but not the inductance.", "Resistance of the wire affects time constant (τ = L/R), but not L itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current through an inductor of 5 H changes at the rate of 2 A/s. The magnitude of the self-induced EMF is:", "explanation": "|ε| = L|dI/dt| = 5 × 2 = 10 V. The self-induced EMF is proportional to both the inductance and the rate of change of current.", "correct_answer": "C", "concept_tags": ["self-inductance", "back-emf", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-08", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 V", "is_correct": false}, {"key": "B", "value": "5 V", "is_correct": false}, {"key": "C", "value": "10 V", "is_correct": true}, {"key": "D", "value": "20 V", "is_correct": false}], "elimination_hints": ["Simply multiply L × dI/dt = 5 × 2 = 10 V.", "2.5 V would result from dividing instead of multiplying.", "The formula is ε = L(dI/dt), not ε = L/2 × (dI/dt)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Mutual inductance between two coils is defined as:", "explanation": "Mutual inductance M₁₂ is the ratio of flux linkage in coil 2 (N₂Φ₂₁) due to current I₁ in coil 1: M = N₂Φ₂₁/I₁. It measures the coupling between two coils. By Neumann''s formula, M₁₂ = M₂₁ = M.", "correct_answer": "A", "concept_tags": ["mutual-inductance", "definition", "flux-linkage"], "payload": {"question_id": "cuet-phy-emi-inductance-09", "subtopic": "mutual inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "M = N₂Φ₂₁/I₁", "is_correct": true}, {"key": "B", "value": "M = N₂Φ₂₁ × I₁", "is_correct": false}, {"key": "C", "value": "M = I₁/(N₂Φ₂₁)", "is_correct": false}, {"key": "D", "value": "M = N₂I₁/Φ₂₁", "is_correct": false}], "elimination_hints": ["M has units of H = Wb/A. N₂Φ₂₁/I₁ gives Wb/A — correct.", "N₂Φ₂₁ × I₁ gives Wb·A, which is not henry.", "Mutual inductance relates flux linkage in one coil to current in another."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mutual inductance between two coaxial solenoids of the same length l, where the inner solenoid has N₁ turns and area A₁, and the outer solenoid has N₂ turns, is:", "explanation": "The field inside the outer solenoid is B₂ = μ₀(N₂/l)I₂. The flux through the inner solenoid = B₂ × A₁ = μ₀(N₂/l)I₂ × A₁. Total flux linkage in inner solenoid = N₁ × μ₀(N₂/l)I₂A₁. So M = N₁Φ/I₂ = μ₀N₁N₂A₁/l.", "correct_answer": "B", "concept_tags": ["mutual-inductance", "coaxial-solenoids", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-10", "subtopic": "mutual inductance of solenoids", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "μ₀N₁N₂A₂/l", "is_correct": false}, {"key": "B", "value": "μ₀N₁N₂A₁/l", "is_correct": true}, {"key": "C", "value": "μ₀N₁N₂(A₁ + A₂)/l", "is_correct": false}, {"key": "D", "value": "μ₀(N₁ + N₂)²A₁/l", "is_correct": false}], "elimination_hints": ["The relevant area is A₁ (inner solenoid), because the flux is confined to its cross-section.", "The outer solenoid''s field is uniform inside, but only the inner area A₁ captures flux.", "M depends on N₁N₂ (product), not (N₁ + N₂)² — mutual inductance involves coupling between two separate coils."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the coefficient of coupling between two coils is k, the mutual inductance M is related to their self-inductances L₁ and L₂ by:", "explanation": "The coefficient of coupling k relates mutual inductance to self-inductances: M = k√(L₁L₂), where 0 ≤ k ≤ 1. k = 1 for perfect coupling (all flux links both coils) and k = 0 for no coupling.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "coupling-coefficient", "self-inductance"], "payload": {"question_id": "cuet-phy-emi-inductance-11", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "M = k(L₁ + L₂)", "is_correct": false}, {"key": "B", "value": "M = k(L₁L₂)", "is_correct": false}, {"key": "C", "value": "M = k√(L₁L₂)", "is_correct": true}, {"key": "D", "value": "M = k√(L₁ + L₂)", "is_correct": false}], "elimination_hints": ["M has units of henry. k is dimensionless, so the expression inside must have units of H.", "k(L₁L₂) has units of H², not H — taking the square root gives the correct units.", "For two identical coils (L₁ = L₂ = L), M = kL, which is consistent with M = k√(L×L)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils have self-inductances L₁ = 4 mH and L₂ = 9 mH. If the coefficient of coupling is 0.5, the mutual inductance is:", "explanation": "M = k√(L₁L₂) = 0.5 × √(4 × 9) = 0.5 × √36 = 0.5 × 6 = 3 mH.", "correct_answer": "B", "concept_tags": ["mutual-inductance", "coupling-coefficient", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-12", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1.5 mH", "is_correct": false}, {"key": "B", "value": "3 mH", "is_correct": true}, {"key": "C", "value": "6 mH", "is_correct": false}, {"key": "D", "value": "18 mH", "is_correct": false}], "elimination_hints": ["√(4 × 9) = √36 = 6 mH. Then multiply by k = 0.5.", "6 mH is M for k = 1 (perfect coupling).", "18 mH would result from L₁ × L₂ without taking the square root."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The EMF induced in a coil due to change of current in a neighbouring coil is given by:", "explanation": "The mutually induced EMF in coil 2 due to changing current in coil 1 is ε₂ = −M(dI₁/dt). M is the mutual inductance between the coils. The negative sign indicates the induced EMF opposes the change (Lenz''s law).", "correct_answer": "A", "concept_tags": ["mutual-inductance", "induced-emf", "rate-of-change"], "payload": {"question_id": "cuet-phy-emi-inductance-13", "subtopic": "mutual induction EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "ε = −M(dI/dt)", "is_correct": true}, {"key": "B", "value": "ε = −L(dI/dt)", "is_correct": false}, {"key": "C", "value": "ε = MI", "is_correct": false}, {"key": "D", "value": "ε = MI²/2", "is_correct": false}], "elimination_hints": ["L(dI/dt) is the self-induced EMF in the same coil, not the mutually induced EMF.", "MI has units of H·A = Wb (flux), not volts.", "The EMF depends on the rate of change of current, not just the current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in an inductor of inductance L carrying a current I is:", "explanation": "The energy stored in the magnetic field of an inductor is U = (1/2)LI². This is analogous to the energy stored in a capacitor U = (1/2)CV². The energy is stored in the magnetic field, not in the current itself.", "correct_answer": "B", "concept_tags": ["energy-stored", "inductor", "magnetic-field-energy"], "payload": {"question_id": "cuet-phy-emi-inductance-14", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "LI²", "is_correct": false}, {"key": "B", "value": "(1/2)LI²", "is_correct": true}, {"key": "C", "value": "LI", "is_correct": false}, {"key": "D", "value": "(1/2)LI", "is_correct": false}], "elimination_hints": ["Analogous to capacitor energy (1/2)CV², the inductor energy has the factor 1/2.", "LI has units of H·A = Wb, not joules.", "(1/2)LI² has units of H·A² = V·s·A = J — correct for energy."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor of 10 H carries a current of 2 A. The energy stored in the inductor is:", "explanation": "U = (1/2)LI² = (1/2) × 10 × (2)² = (1/2) × 10 × 4 = 20 J.", "correct_answer": "C", "concept_tags": ["energy-stored", "inductor", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-15", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "5 J", "is_correct": false}, {"key": "B", "value": "10 J", "is_correct": false}, {"key": "C", "value": "20 J", "is_correct": true}, {"key": "D", "value": "40 J", "is_correct": false}], "elimination_hints": ["U = (1/2) × 10 × 4 = 20 J. Don''t forget to square the current.", "10 J results from forgetting to square I: (1/2) × 10 × 2 = 10.", "40 J results from omitting the factor of 1/2."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic energy density (energy per unit volume) in a region of magnetic field B is:", "explanation": "The energy stored per unit volume in a magnetic field is u = B²/(2μ₀). This is analogous to the electric energy density u = (1/2)ε₀E². For a solenoid, the total energy U = u × Volume = [B²/(2μ₀)] × Al.", "correct_answer": "A", "concept_tags": ["energy-density", "magnetic-field", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-16", "subtopic": "magnetic energy density", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "B²/(2μ₀)", "is_correct": true}, {"key": "B", "value": "B/(2μ₀)", "is_correct": false}, {"key": "C", "value": "2B²/μ₀", "is_correct": false}, {"key": "D", "value": "μ₀B²/2", "is_correct": false}], "elimination_hints": ["B/(2μ₀) has units of T/(H/m) = A/m, which is not J/m³.", "B²/(2μ₀) has units of T²/(H/m) = J/m³ — correct for energy density.", "μ₀B²/2 has units of (H/m)·T² = incorrect dimensions."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils of self-inductances 2 mH and 8 mH are placed so close together that the effective flux in one coil is completely linked with the other. The mutual inductance between them is:", "explanation": "For perfect coupling (k = 1), M = k√(L₁L₂) = 1 × √(2 × 8) = √16 = 4 mH.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "perfect-coupling", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-17", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "2 mH", "is_correct": false}, {"key": "B", "value": "3 mH", "is_correct": false}, {"key": "C", "value": "4 mH", "is_correct": true}, {"key": "D", "value": "16 mH", "is_correct": false}], "elimination_hints": ["''Completely linked'' means k = 1 (perfect coupling).", "M = √(L₁L₂) = √(2 × 8) = √16 = 4 mH.", "16 mH is L₁ × L₂ without taking the square root."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a soft iron core is inserted into a solenoid, its self-inductance:", "explanation": "Self-inductance L = μN²A/l, where μ = μ₀μᵣ. Soft iron has a high relative permeability (μᵣ >> 1), so inserting it increases μ and hence L increases significantly. This is why iron cores are used in inductors and transformers.", "correct_answer": "A", "concept_tags": ["self-inductance", "iron-core", "permeability"], "payload": {"question_id": "cuet-phy-emi-inductance-18", "subtopic": "effect of core material", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Increases", "is_correct": true}, {"key": "B", "value": "Decreases", "is_correct": false}, {"key": "C", "value": "Remains unchanged", "is_correct": false}, {"key": "D", "value": "Becomes zero", "is_correct": false}], "elimination_hints": ["Iron is ferromagnetic with μᵣ >> 1, which multiplies the inductance.", "L = μ₀μᵣN²A/l — increasing μᵣ directly increases L.", "Only a superconducting shield (perfect diamagnet) could reduce L toward zero."]}}]'::jsonb, 'deploy-2026-03-05-b05');

